-- === Genesis Chapters 26-27 ===
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Ch26 Kids
('Genesis', 26, 'kids', 1, 'Who told people that Rebekah was his sister instead of his wife?', 'Isaac', 'Abraham', 'Jacob', 'Esau', 'a', 'Isaac said Rebekah was his sister because he was afraid. See Genesis 26:7.'),
('Genesis', 26, 'kids', 2, 'What did Isaac dig in the land?', 'Tunnels', 'Wells', 'Graves', 'Caves', 'b', 'Isaac''s servants dug wells in the valley. See Genesis 26:18-19.'),
('Genesis', 26, 'kids', 3, 'What was the name of the king Isaac dealt with?', 'Pharaoh', 'Nebuchadnezzar', 'Abimelech', 'Herod', 'c', 'Abimelech was king of the Philistines. See Genesis 26:1.'),
-- Ch26 Teens
('Genesis', 26, 'teens', 1, 'Why did Isaac go to Gerar instead of Egypt during the famine?', 'He was too old to travel far', 'The road was blocked', 'Rebekah refused to go', 'God told him not to go to Egypt', 'd', 'The LORD appeared to Isaac and said "Go not down into Egypt." See Genesis 26:2.'),
('Genesis', 26, 'teens', 2, 'What were the names of the first two wells that caused strife?', 'Beersheba and Rehoboth', 'Esek and Sitnah', 'Gerar and Moriah', 'Lahai-roi and Shur', 'b', 'They called them Esek (contention) and Sitnah (hatred). See Genesis 26:20-21.'),
('Genesis', 26, 'teens', 3, 'What does the name Rehoboth mean?', 'Peace', 'Victory', 'Living water', 'The LORD hath made room for us', 'd', 'Isaac said "the LORD hath made room for us." See Genesis 26:22.'),
('Genesis', 26, 'teens', 4, 'Why did Abimelech come to Isaac at Beersheba?', 'To make a covenant of peace', 'To wage war', 'To buy grain', 'To return stolen goods', 'a', 'Abimelech sought a covenant because he saw the LORD was with Isaac. See Genesis 26:28.'),
('Genesis', 26, 'teens', 5, 'What grief did Esau''s wives cause Isaac and Rebekah?', 'They were idol worshippers', 'They stole from them', 'They were a grief of mind because they were Hittite women', 'They refused to help the family', 'c', 'Esau''s Hittite wives were a grief of mind to Isaac and Rebekah. See Genesis 26:34-35.'),
-- Ch26 Adults
('Genesis', 26, 'adults', 1, 'God''s promise to Isaac in Genesis 26:3-4 echoes which earlier covenant?', 'The covenant with Noah', 'The covenant with Melchizedek', 'The covenant with Adam', 'The covenant with Abraham', 'd', 'God reaffirmed the Abrahamic covenant: multiplied seed, all nations blessed. See Genesis 26:3-4.'),
('Genesis', 26, 'adults', 2, 'What reason did God give for confirming His promises to Isaac?', 'Isaac''s own righteousness', 'Because of Rebekah''s faith', 'Because Abraham obeyed God''s voice and kept His commandments', 'Because Isaac built an altar', 'c', 'God said "Because that Abraham obeyed my voice, and kept my charge." See Genesis 26:5.'),
('Genesis', 26, 'adults', 3, 'How did Abimelech discover that Rebekah was Isaac''s wife?', 'A servant confessed', 'He saw Isaac sporting with Rebekah', 'Rebekah told him herself', 'He found their marriage record', 'b', 'Abimelech looked out a window and saw Isaac sporting with Rebekah. See Genesis 26:8.'),
('Genesis', 26, 'adults', 4, 'How successful was Isaac''s farming in Gerar?', 'He received a hundredfold in the same year', 'He barely survived', 'He lost everything to drought', 'He received tenfold', 'a', 'Isaac sowed and received a hundredfold, and the LORD blessed him. See Genesis 26:12.'),
('Genesis', 26, 'adults', 5, 'What did the Philistines do to Abraham''s wells after his death?', 'They poisoned them', 'They built walls around them', 'They filled them with earth', 'They claimed ownership', 'c', 'The Philistines had stopped and filled Abraham''s wells with earth. See Genesis 26:15.'),
('Genesis', 26, 'adults', 6, 'Who accompanied Abimelech when he came to make a covenant with Isaac?', 'Ahuzzath his friend and Phichol the chief captain', 'His army commander only', 'His wife and sons', 'The elders of Gerar', 'a', 'Abimelech came with Ahuzzath his friend and Phichol the chief captain. See Genesis 26:26.'),
('Genesis', 26, 'adults', 7, 'What did Isaac''s servants find on the same day Abimelech departed?', 'Gold', 'An ancient altar', 'A lost flock', 'A well of water', 'd', 'Isaac''s servants told him about a well they had digged and found water. See Genesis 26:32.'),
('Genesis', 26, 'adults', 8, 'What were the names of Esau''s two Hittite wives mentioned in this chapter?', 'Adah and Zillah', 'Judith and Bashemath', 'Leah and Rachel', 'Bilhah and Zilpah', 'b', 'Esau married Judith daughter of Beeri and Bashemath daughter of Elon. See Genesis 26:34.'),
-- Ch27 Kids
('Genesis', 27, 'kids', 1, 'Who helped Jacob trick his father Isaac?', 'Rebekah', 'Rachel', 'Leah', 'Sarah', 'a', 'Rebekah told Jacob how to disguise himself and get the blessing. See Genesis 27:6-10.'),
('Genesis', 27, 'kids', 2, 'What did Jacob put on his hands and neck to feel hairy like Esau?', 'Wool', 'Goat skins', 'Fur from a bear', 'Cotton', 'b', 'Rebekah put goat skins on Jacob''s hands and neck. See Genesis 27:16.'),
('Genesis', 27, 'kids', 3, 'What did Esau do when he found out Jacob took his blessing?', 'He laughed', 'He ran away', 'He cried with a great and bitter cry', 'He celebrated', 'c', 'Esau cried with a great and exceeding bitter cry. See Genesis 27:34.'),
-- Ch27 Teens
('Genesis', 27, 'teens', 1, 'Why was Isaac unable to see who was really before him?', 'It was dark in the tent', 'Jacob stood far away', 'He was blindfolded', 'His eyes were dim with age', 'd', 'Isaac was old and his eyes were dim so he could not see. See Genesis 27:1.'),
('Genesis', 27, 'teens', 2, 'What food did Isaac ask Esau to prepare before giving the blessing?', 'Lamb stew', 'Savoury meat from venison', 'Bread and cheese', 'Fish and herbs', 'b', 'Isaac asked Esau to hunt venison and make savoury meat. See Genesis 27:3-4.'),
('Genesis', 27, 'teens', 3, 'What did Isaac notice about the voice versus the hands?', 'Nothing unusual', 'The voice was too deep', 'The hands were too smooth', 'The voice is Jacob''s voice, but the hands are the hands of Esau', 'd', 'Isaac noted the voice was Jacob''s but the hands were Esau''s. See Genesis 27:22.'),
('Genesis', 27, 'teens', 4, 'What blessing did Isaac give to Esau after Jacob took the first?', 'He would live by his sword and serve his brother but eventually break free', 'He would be a great king', 'He would inherit the promised land', 'He would have more children than Jacob', 'a', 'Isaac said Esau would live by his sword and serve his brother but break his yoke. See Genesis 27:39-40.'),
('Genesis', 27, 'teens', 5, 'Where did Rebekah tell Jacob to flee to escape Esau''s anger?', 'Egypt', 'Beersheba', 'Haran, to her brother Laban', 'Canaan', 'c', 'Rebekah told Jacob to flee to Laban her brother in Haran. See Genesis 27:43.'),
-- Ch27 Adults
('Genesis', 27, 'adults', 1, 'In Isaac''s blessing of Jacob, what specific blessings were promised?', 'Flocks and herds', 'Olive groves and vineyards', 'Gold and silver', 'The dew of heaven and the fatness of the earth, plenty of corn and wine', 'd', 'Isaac blessed Jacob with dew of heaven, fatness of earth, corn and wine. See Genesis 27:28.'),
('Genesis', 27, 'adults', 2, 'What political authority did Isaac''s blessing confer on Jacob?', 'Kingship over Israel', 'Priesthood', 'Lordship over his brethren, with nations bowing down', 'Judgeship over the tribes', 'c', 'Isaac said "Be lord over thy brethren, let thy mother''s sons bow down to thee." See Genesis 27:29.'),
('Genesis', 27, 'adults', 3, 'How did Jacob describe himself to his mother when she proposed the deception?', 'A strong hunter', 'A smooth man, unlike Esau who was hairy', 'A righteous man', 'A simple man', 'b', 'Jacob said "Esau my brother is a hairy man, and I am a smooth man." See Genesis 27:11.'),
('Genesis', 27, 'adults', 4, 'What curse did Rebekah say she would bear if the deception failed?', 'Upon me be thy curse, my son', 'Banishment from the family', 'Death', 'Loss of inheritance', 'a', 'Rebekah said "Upon me be thy curse, my son." See Genesis 27:13.'),
('Genesis', 27, 'adults', 5, 'When Isaac discovered the deception, what did he say about the blessing?', 'He retracted it', 'He split it between both sons', 'I have blessed him, yea and he shall be blessed', 'He cursed Jacob', 'c', 'Isaac confirmed the blessing could not be revoked. See Genesis 27:33.'),
('Genesis', 27, 'adults', 6, 'What did Esau resolve to do after losing his blessing?', 'Kill Jacob after the days of mourning for Isaac', 'Seek his own blessing elsewhere', 'Leave the family forever', 'Appeal to God directly', 'a', 'Esau said he would slay his brother after their father''s death. See Genesis 27:41.'),
('Genesis', 27, 'adults', 7, 'What excuse did Rebekah give Isaac for sending Jacob away?', 'She feared Esau would kill him', 'She had a dream from God', 'She wanted Jacob to study with Laban', 'She was weary of life because of Heth''s daughters and did not want Jacob to marry one', 'd', 'Rebekah told Isaac she was weary because of Heth''s daughters. See Genesis 27:46.'),
('Genesis', 27, 'adults', 8, 'What is the theological significance of Isaac''s inability to revoke the blessing?', 'Isaac was too weak to argue', 'It reflects the irrevocable nature of patriarchal blessings spoken under divine authority', 'He simply forgot what he said', 'He secretly preferred Jacob', 'b', 'The patriarchal blessing was considered divinely binding. See Genesis 27:33 and Hebrews 12:17.');

-- ═══ Genesis Chapters 28–29 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Ch28 Kids
('Genesis', 28, 'kids', 1, 'What did Jacob see in his dream at Bethel?', 'A ladder reaching to heaven with angels going up and down', 'A burning bush', 'A rainbow', 'A great flood', 'a', 'Jacob dreamed of a ladder with angels ascending and descending. See Genesis 28:12.'),
('Genesis', 28, 'kids', 2, 'What did Jacob use as a pillow when he slept?', 'A blanket', 'A stone', 'A pile of leaves', 'A saddle', 'b', 'Jacob took stones and put them for his pillows. See Genesis 28:11.'),
('Genesis', 28, 'kids', 3, 'What did Jacob name the place where he had the dream?', 'Jerusalem', 'Eden', 'Bethel', 'Nazareth', 'c', 'Jacob called the place Bethel, meaning house of God. See Genesis 28:19.'),
-- Ch28 Teens
('Genesis', 28, 'teens', 1, 'Why did Isaac send Jacob to Padanaram?', 'To learn farming', 'To trade livestock', 'To escape a famine', 'To find a wife from Laban''s family rather than from the Canaanites', 'd', 'Isaac charged Jacob not to take a Canaanite wife but to go to Laban''s house. See Genesis 28:1-2.'),
('Genesis', 28, 'teens', 2, 'What was the original name of Bethel before Jacob renamed it?', 'Salem', 'Luz', 'Moriah', 'Beersheba', 'b', 'The name of the city was called Luz at the first. See Genesis 28:19.'),
('Genesis', 28, 'teens', 3, 'What did God promise Jacob in the dream?', 'A long life', 'Great wealth immediately', 'Victory in battle', 'The land, countless descendants, and that all families of earth would be blessed through him', 'd', 'God promised the land, seed as the dust, and blessing to all families. See Genesis 28:13-14.'),
('Genesis', 28, 'teens', 4, 'What did Jacob do with the stone pillow in the morning?', 'Set it up as a pillar and poured oil on it', 'Threw it away', 'Built a house with it', 'Carved his name on it', 'a', 'Jacob set up the stone as a pillar and poured oil on the top of it. See Genesis 28:18.'),
('Genesis', 28, 'teens', 5, 'What vow did Jacob make to God at Bethel?', 'He would never sin again', 'He would build a temple', 'If God would be with him and provide, the LORD would be his God and he would give a tenth', 'He would never leave Canaan', 'c', 'Jacob vowed that God would be his God and he would give a tenth. See Genesis 28:20-22.'),
-- Ch28 Adults
('Genesis', 28, 'adults', 1, 'What did Esau do when he saw Isaac had blessed Jacob and sent him to Padanaram?', 'He followed Jacob', 'He made peace with Jacob', 'He moved to Egypt', 'He went to Ishmael and married Mahalath, Ishmael''s daughter', 'd', 'Esau went to Ishmael and took Mahalath as wife. See Genesis 28:8-9.'),
('Genesis', 28, 'adults', 2, 'In Jacob''s dream, where did the LORD stand?', 'At the bottom of the ladder', 'Beside Jacob', 'Above the ladder', 'In the clouds', 'c', 'The LORD stood above the ladder and spoke to Jacob. See Genesis 28:13.'),
('Genesis', 28, 'adults', 3, 'What specific directional expansion did God promise Jacob''s descendants?', 'North and south only', 'To the west, east, north, and south', 'Across the sea', 'Only within Canaan''s borders', 'b', 'God said thou shalt spread abroad to the west, east, north, and south. See Genesis 28:14.'),
('Genesis', 28, 'adults', 4, 'What was Jacob''s first reaction upon waking from the dream?', 'He was afraid and said how dreadful is this place', 'Joy', 'He laughed', 'He immediately prayed', 'a', 'Jacob was afraid and said "How dreadful is this place!" See Genesis 28:17.'),
('Genesis', 28, 'adults', 5, 'What did Jacob call Bethel besides house of God?', 'Stairway to heaven', 'God''s dwelling', 'The gate of heaven', 'The holy mountain', 'c', 'Jacob said this is none other but the house of God and the gate of heaven. See Genesis 28:17.'),
('Genesis', 28, 'adults', 6, 'Jacob''s vow in 28:20-22 is conditional. What conditions did he set?', 'If God will be with him, keep him, give him bread and raiment, and bring him back in peace', 'If God makes him wealthy and powerful', 'If God defeats his enemies', 'If God gives him many sons', 'a', 'Jacob asked for God''s presence, protection, provision, and safe return. See Genesis 28:20-21.'),
('Genesis', 28, 'adults', 7, 'Who was Mahalath''s father, the wife Esau took from Ishmael''s family?', 'Abraham', 'Nahor', 'Lot', 'Ishmael', 'd', 'Esau married Mahalath the daughter of Ishmael. See Genesis 28:9.'),
('Genesis', 28, 'adults', 8, 'How does Jacob''s Bethel experience connect to Jesus'' words in John 1:51?', 'Jesus mentions a pillar of stone', 'Jesus tells Nathanael he will see heaven open and angels ascending and descending upon the Son of man', 'Jesus visits Bethel himself', 'Jesus rebukes Nathanael using Jacob''s story', 'b', 'Jesus identified Himself as the true ladder between heaven and earth. See John 1:51 and Genesis 28:12.'),
-- Ch29 Kids
('Genesis', 29, 'kids', 1, 'Who did Jacob meet at the well?', 'Rachel', 'Rebekah', 'Leah', 'Sarah', 'a', 'Jacob met Rachel at the well as she came with her father''s sheep. See Genesis 29:9-10.'),
('Genesis', 29, 'kids', 2, 'How many years did Jacob agree to work for Laban to marry Rachel?', 'Three years', 'Seven years', 'Five years', 'Ten years', 'b', 'Jacob served seven years for Rachel. See Genesis 29:18.'),
('Genesis', 29, 'kids', 3, 'Who did Laban trick Jacob into marrying first?', 'Rachel', 'Bilhah', 'Leah', 'Zilpah', 'c', 'Laban gave Leah to Jacob instead of Rachel. See Genesis 29:23-25.'),
-- Ch29 Teens
('Genesis', 29, 'teens', 1, 'What was Rachel''s job when Jacob first saw her?', 'She was weaving cloth', 'She was selling goods at market', 'She was drawing water', 'She was a shepherdess tending her father''s sheep', 'd', 'Rachel came with her father''s sheep, for she kept them. See Genesis 29:9.'),
('Genesis', 29, 'teens', 2, 'What did Jacob do when he first met Rachel at the well?', 'He gave her gifts', 'He rolled the stone from the well''s mouth, watered her flock, kissed her, and wept', 'He invited her to dinner', 'He asked permission to speak to her', 'b', 'Jacob rolled the stone, watered the flock, kissed Rachel, and wept. See Genesis 29:10-11.'),
('Genesis', 29, 'teens', 3, 'How did the seven years Jacob worked for Rachel seem to him?', 'Like an eternity', 'Very long and difficult', 'Like a punishment', 'Like only a few days because of his love for her', 'd', 'They seemed unto him but a few days, for the love he had to her. See Genesis 29:20.'),
('Genesis', 29, 'teens', 4, 'What excuse did Laban give for substituting Leah for Rachel?', 'It was the custom that the firstborn must marry before the younger', 'Rachel was too young', 'Rachel was sick', 'He had promised Leah to Jacob already', 'a', 'Laban said it was not done in their country to give the younger before the firstborn. See Genesis 29:26.'),
('Genesis', 29, 'teens', 5, 'What does the name Reuben relate to?', 'He looked like Esau', 'He was born at sunrise', 'The LORD had looked upon Leah''s affliction', 'He was the strongest baby', 'c', 'Leah said "the LORD hath looked upon my affliction." See Genesis 29:32.'),
-- Ch29 Adults
('Genesis', 29, 'adults', 1, 'How is Leah physically described in contrast to Rachel?', 'Leah was short, Rachel was tall', 'No physical differences are mentioned', 'Leah was dark-haired, Rachel was fair', 'Leah was tender eyed; Rachel was beautiful and well favoured', 'd', 'Leah was tender eyed but Rachel was beautiful and well favoured. See Genesis 29:17.'),
('Genesis', 29, 'adults', 2, 'How many sons did Leah bear to Jacob in this chapter?', 'Two', 'Three', 'Four', 'Six', 'c', 'Leah bore Reuben, Simeon, Levi, and Judah in this chapter. See Genesis 29:32-35.'),
('Genesis', 29, 'adults', 3, 'What is the meaning of the name Simeon?', 'God has blessed me', 'The LORD heard that I was hated', 'My husband will love me', 'Praise the LORD', 'b', 'Leah said "Because the LORD hath heard that I was hated." See Genesis 29:33.'),
('Genesis', 29, 'adults', 4, 'What did Leah say when she named her son Levi?', 'Now this time will my husband be joined unto me', 'The LORD has heard me', 'Now will I praise the LORD', 'God has looked upon me', 'a', 'Leah hoped her husband would be joined to her. See Genesis 29:34.'),
('Genesis', 29, 'adults', 5, 'After Judah was born, what did Leah say?', 'Now my husband will love me', 'God has given me another son', 'Now will I praise the LORD', 'I have borne enough sons', 'c', 'Leah said "Now will I praise the LORD" and called him Judah. See Genesis 29:35.'),
('Genesis', 29, 'adults', 6, 'What is the relationship between Laban and Rebekah?', 'Laban was Rebekah''s brother', 'They were cousins', 'Laban was Rebekah''s uncle', 'They were not related', 'a', 'Laban was Rebekah''s brother. See Genesis 29:5 and Genesis 24:29.'),
('Genesis', 29, 'adults', 7, 'What was Jacob''s total labor commitment to earn Rachel as his wife?', 'Seven years', 'Ten years', 'Seven years plus a bride price', 'Fourteen years of labor', 'd', 'Jacob served seven years, was tricked, then served another seven. See Genesis 29:27-30.'),
('Genesis', 29, 'adults', 8, 'What theological pattern does God''s opening of Leah''s womb while Rachel was barren establish?', 'God punishes disobedience', 'God shows compassion to the unloved and works through unexpected means', 'God favors older siblings', 'God rewards hard work', 'b', 'When the LORD saw Leah was hated, he opened her womb. See Genesis 29:31.');

-- ═══ Genesis Chapters 30–31 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Ch30 Kids
('Genesis', 30, 'kids', 1, 'What did Rachel ask Jacob to give her?', 'Children', 'Gold and silver', 'A new home', 'More sheep', 'a', 'Rachel said to Jacob "Give me children, or else I die." See Genesis 30:1.'),
('Genesis', 30, 'kids', 2, 'What kind of animals did Jacob ask for as his wages from Laban?', 'All the white sheep', 'The speckled and spotted ones', 'The biggest goats', 'The youngest lambs', 'b', 'Jacob asked for the speckled and spotted cattle and goats. See Genesis 30:32.'),
('Genesis', 30, 'kids', 3, 'What was the name of Rachel''s first son?', 'Benjamin', 'Dan', 'Joseph', 'Reuben', 'c', 'God remembered Rachel and she bore a son named Joseph. See Genesis 30:22-24.'),
-- Ch30 Teens
('Genesis', 30, 'teens', 1, 'Which handmaid did Rachel give to Jacob to bear children on her behalf?', 'Zilpah', 'Deborah', 'Hagar', 'Bilhah', 'd', 'Rachel gave Jacob Bilhah her handmaid. See Genesis 30:3-4.'),
('Genesis', 30, 'teens', 2, 'Which handmaid did Leah give to Jacob?', 'Bilhah', 'Zilpah', 'Hagar', 'Keturah', 'b', 'Leah gave Jacob Zilpah her maid. See Genesis 30:9.'),
('Genesis', 30, 'teens', 3, 'What plant did Reuben find in the field that Rachel wanted?', 'Figs', 'Grapes', 'Olives', 'Mandrakes', 'd', 'Reuben found mandrakes in the field. See Genesis 30:14.'),
('Genesis', 30, 'teens', 4, 'What was the name of the only daughter of Jacob mentioned in Genesis?', 'Dinah', 'Rachel', 'Tamar', 'Miriam', 'a', 'Leah bore a daughter and called her name Dinah. See Genesis 30:21.'),
('Genesis', 30, 'teens', 5, 'What did Laban realize about why he had prospered?', 'He was a skilled farmer', 'He had good land', 'The LORD had blessed him for Jacob''s sake', 'He worked harder than others', 'c', 'Laban said "I have learned by experience that the LORD hath blessed me for thy sake." See Genesis 30:27.'),
-- Ch30 Adults
('Genesis', 30, 'adults', 1, 'What does the name Dan mean, as given by Rachel?', 'My struggle', 'He is mighty', 'God has blessed me', 'God hath judged me and heard my voice', 'd', 'Rachel said "God hath judged me, and hath also heard my voice." See Genesis 30:6.'),
('Genesis', 30, 'adults', 2, 'What does the name Naphtali signify?', 'God''s gift', 'Fruitful vine', 'With great wrestlings have I wrestled with my sister', 'God has added', 'c', 'Rachel said "With great wrestlings have I wrestled with my sister." See Genesis 30:8.'),
('Genesis', 30, 'adults', 3, 'What does the name Issachar relate to?', 'God has heard me', 'God hath given me my hire because I gave my maiden to my husband', 'Dwelling by the sea', 'A strong donkey', 'b', 'Leah said "God hath given me my hire." See Genesis 30:18.'),
('Genesis', 30, 'adults', 4, 'What does the name Zebulun mean according to Leah?', 'God hath endued me with a good dowry; now will my husband dwell with me', 'God has blessed me', 'A fruitful bough', 'God has judged', 'a', 'Leah said "now will my husband dwell with me." See Genesis 30:20.'),
('Genesis', 30, 'adults', 5, 'What does the name Gad mean?', 'Good fortune', 'Great warrior', 'A troop cometh', 'Blessed one', 'c', 'Leah said "A troop cometh" and called his name Gad. See Genesis 30:11.'),
('Genesis', 30, 'adults', 6, 'What strategy did Jacob use with rods of poplar, hazel, and chestnut?', 'He peeled white strakes in them and set them before the flocks at watering troughs', 'He built fences', 'He used them as walking sticks', 'He burned them as offerings', 'a', 'Jacob placed peeled rods in the gutters before the breeding flocks. See Genesis 30:37-39.'),
('Genesis', 30, 'adults', 7, 'How did Jacob selectively breed the stronger animals?', 'He separated them by color', 'He kept them in separate pastures', 'He fed them different food', 'He set the rods before the stronger cattle but not the feebler ones', 'd', 'Jacob laid the rods before the stronger cattle and not the feebler. See Genesis 30:41-42.'),
('Genesis', 30, 'adults', 8, 'What was the result of Jacob''s livestock strategy?', 'He remained poor', 'He increased exceedingly with large flocks, maidservants, menservants, camels, and asses', 'He gained moderately', 'He lost most of his flock', 'b', 'The man increased exceedingly and had much cattle. See Genesis 30:43.'),
-- Ch31 Kids
('Genesis', 31, 'kids', 1, 'Why did Jacob decide to leave Laban?', 'Laban and his sons were no longer friendly toward him', 'He missed his home', 'He ran out of food', 'Rachel asked him to leave', 'a', 'Jacob saw that Laban''s countenance was not toward him as before. See Genesis 31:2.'),
('Genesis', 31, 'kids', 2, 'What did Rachel steal from her father Laban?', 'His money', 'His household gods', 'His best sheep', 'His clothing', 'b', 'Rachel had stolen the images (teraphim) that were her father''s. See Genesis 31:19.'),
('Genesis', 31, 'kids', 3, 'Did Laban find his stolen household gods?', 'Yes, he found them right away', 'Yes, Jacob gave them back', 'No, Rachel hid them and he did not find them', 'No, they were destroyed', 'c', 'Rachel sat on the images and Laban searched but found them not. See Genesis 31:34-35.'),
-- Ch31 Teens
('Genesis', 31, 'teens', 1, 'How did God tell Jacob to leave Laban?', 'Through a prophet', 'Through Rachel', 'Through an angel in a dream', 'God spoke to Jacob and said return unto the land of thy fathers', 'd', 'The LORD said unto Jacob "Return unto the land of thy fathers." See Genesis 31:3.'),
('Genesis', 31, 'teens', 2, 'How many times did Laban change Jacob''s wages according to Jacob?', 'Three times', 'Ten times', 'Five times', 'Twenty times', 'b', 'Jacob said Laban had changed his wages ten times. See Genesis 31:7.'),
('Genesis', 31, 'teens', 3, 'How did Rachel hide the household gods from Laban?', 'She buried them in the ground', 'She gave them to a servant', 'She hid them in a well', 'She sat upon them and said she could not rise because of her monthly period', 'd', 'Rachel sat upon the camel''s furniture with the images inside and said she could not rise. See Genesis 31:34-35.'),
('Genesis', 31, 'teens', 4, 'What covenant did Laban and Jacob make?', 'A covenant at Mizpah with a heap of stones as witness', 'A trade agreement', 'A marriage contract', 'A military alliance', 'a', 'They made a covenant at Mizpah with a pillar and heap. See Genesis 31:44-49.'),
('Genesis', 31, 'teens', 5, 'What does the name Mizpah mean in the covenant context?', 'Place of rest', 'God is great', 'The LORD watch between me and thee when we are absent one from another', 'Border of peace', 'c', 'Laban said "The LORD watch between me and thee." See Genesis 31:49.'),
-- Ch31 Adults
('Genesis', 31, 'adults', 1, 'How long did Jacob serve Laban in total?', 'Fourteen years', 'Twenty-five years', 'Eighteen years', 'Twenty years', 'd', 'Jacob served fourteen years for the two daughters and six years for the cattle. See Genesis 31:41.'),
('Genesis', 31, 'adults', 2, 'What did God say to Laban in a dream before he caught up with Jacob?', 'Destroy Jacob', 'Forgive Jacob freely', 'Take heed that thou speak not to Jacob either good or bad', 'Return home immediately', 'c', 'God warned Laban not to speak to Jacob either good or bad. See Genesis 31:24.'),
('Genesis', 31, 'adults', 3, 'How did Jacob describe his service to Laban?', 'It was easy and pleasant', 'In the day drought consumed him and frost by night, and sleep departed from his eyes', 'He had rest every Sabbath', 'Laban treated him well', 'b', 'Jacob described harsh conditions of drought, frost, and sleeplessness. See Genesis 31:40.'),
('Genesis', 31, 'adults', 4, 'What did Jacob say would have happened if God had not been on his side?', 'Laban would have sent him away empty', 'He would have stayed longer', 'He would have become wealthy sooner', 'Nothing different', 'a', 'Jacob said Laban would have sent him away empty except God intervened. See Genesis 31:42.'),
('Genesis', 31, 'adults', 5, 'What names did Laban and Jacob give to the heap of witness?', 'Ebenezer and Bethel', 'Peniel and Mahanaim', 'Jegar-sahadutha (Laban) and Galeed (Jacob)', 'Mizpah and Gilead', 'c', 'Laban called it Jegar-sahadutha (Aramaic) and Jacob called it Galeed (Hebrew). See Genesis 31:47.'),
('Genesis', 31, 'adults', 6, 'What angel did Jacob reference when explaining how God showed him to breed the cattle?', 'The angel of God who spoke in a dream', 'Michael', 'Gabriel', 'The angel of the LORD at the bush', 'a', 'The angel of God spoke to Jacob in a dream about the cattle. See Genesis 31:11-12.'),
('Genesis', 31, 'adults', 7, 'What specific charge did Laban make the covenant cover regarding Jacob''s treatment of his daughters?', 'That Jacob would not make them work', 'That Jacob would give them an inheritance', 'That Jacob would send them home yearly', 'That Jacob would not afflict his daughters nor take other wives besides them', 'd', 'Laban said "If thou shalt afflict my daughters, or if thou shalt take other wives." See Genesis 31:50.'),
('Genesis', 31, 'adults', 8, 'By whose God did Jacob swear at the Mizpah covenant?', 'The God of Abraham', 'The fear of his father Isaac', 'The God of Nahor', 'The Most High God', 'b', 'Jacob sware by the fear of his father Isaac. See Genesis 31:53.');

-- ═══ Genesis Chapters 32–33 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Ch32 Kids
('Genesis', 32, 'kids', 1, 'Who did Jacob wrestle with all night?', 'An angel (a man)', 'Laban', 'Esau', 'A soldier', 'a', 'Jacob wrestled with a man until the breaking of day. See Genesis 32:24.'),
('Genesis', 32, 'kids', 2, 'What new name did Jacob receive after the wrestling?', 'Abraham', 'Israel', 'Judah', 'Daniel', 'b', 'His name was changed to Israel. See Genesis 32:28.'),
('Genesis', 32, 'kids', 3, 'What did Jacob send ahead as gifts to Esau?', 'Gold and jewels', 'Clothing and perfume', 'Goats, sheep, camels, cattle, and donkeys', 'Bread and wine', 'c', 'Jacob sent goats, sheep, camels, cows, bulls, and donkeys. See Genesis 32:14-15.'),
-- Ch32 Teens
('Genesis', 32, 'teens', 1, 'What river did Jacob cross the night he wrestled with the angel?', 'The Jordan', 'The Euphrates', 'The Nile', 'The Jabbok', 'd', 'Jacob was left alone after crossing the ford of Jabbok. See Genesis 32:22-24.'),
('Genesis', 32, 'teens', 2, 'How many men was Esau coming with when Jacob heard the news?', 'One hundred', 'Four hundred', 'Two hundred', 'Six hundred', 'b', 'Esau was coming with four hundred men. See Genesis 32:6.'),
('Genesis', 32, 'teens', 3, 'What did the angel do to Jacob during the wrestling match?', 'Knocked him down', 'Pushed him into the river', 'Struck him on the head', 'Touched the hollow of his thigh, putting it out of joint', 'd', 'He touched the hollow of Jacob''s thigh and it was out of joint. See Genesis 32:25.'),
('Genesis', 32, 'teens', 4, 'What did Jacob demand before letting the angel go?', 'A blessing', 'A vision of God', 'Protection from Esau', 'A promise of wealth', 'a', 'Jacob said "I will not let thee go, except thou bless me." See Genesis 32:26.'),
('Genesis', 32, 'teens', 5, 'What does the name Israel mean?', 'Man of God', 'Chosen one', 'A prince who has power with God and with men, and has prevailed', 'Wrestler', 'c', 'He said "thou hast power with God and with men, and hast prevailed." See Genesis 32:28.'),
-- Ch32 Adults
('Genesis', 32, 'adults', 1, 'What did Jacob name the place where he met angels of God at the beginning of the chapter?', 'Bethel', 'Succoth', 'Peniel', 'Mahanaim', 'd', 'Jacob called the place Mahanaim, meaning two hosts or two camps. See Genesis 32:2.'),
('Genesis', 32, 'adults', 2, 'What strategy did Jacob use to protect his family from Esau?', 'He built a fortress', 'He hired soldiers', 'He divided his people and flocks into two bands so if one was attacked the other could escape', 'He hid in a cave', 'c', 'Jacob divided his company into two bands for safety. See Genesis 32:7-8.'),
('Genesis', 32, 'adults', 3, 'In Jacob''s prayer before meeting Esau, what covenant promise did he invoke?', 'The promise to Noah', 'God''s promise to do him good and make his seed as the sand of the sea', 'The promise to Adam', 'The promise to Melchizedek', 'b', 'Jacob reminded God of the promise to make his seed as the sand. See Genesis 32:12.'),
('Genesis', 32, 'adults', 4, 'What did Jacob call the place where he wrestled with God?', 'Peniel, for I have seen God face to face and my life is preserved', 'Bethel', 'Mahanaim', 'Jabbok', 'a', 'Jacob called it Peniel: "I have seen God face to face." See Genesis 32:30.'),
('Genesis', 32, 'adults', 5, 'Why do the children of Israel not eat the sinew of the thigh?', 'It was considered unclean', 'Moses commanded it later', 'Because the angel touched the hollow of Jacob''s thigh in the sinew that shrank', 'It was a Canaanite custom', 'c', 'The children of Israel eat not the sinew which shrank because of the angel''s touch. See Genesis 32:32.'),
('Genesis', 32, 'adults', 6, 'How did Jacob describe himself in his prayer to God?', 'As unworthy of the least of all God''s mercies and truth', 'As a mighty prince', 'As the heir of Abraham', 'As a righteous man', 'a', 'Jacob said "I am not worthy of the least of all the mercies." See Genesis 32:10.'),
('Genesis', 32, 'adults', 7, 'What did Jacob instruct his servants to say when Esau met each drove of gifts?', 'Jacob is a wealthy man', 'Jacob has come to trade', 'Jacob wishes peace', 'They be thy servant Jacob''s; it is a present sent unto my lord Esau; and behold also he is behind us', 'd', 'Each servant was to say the gifts were a present for lord Esau. See Genesis 32:18.'),
('Genesis', 32, 'adults', 8, 'Why did the angel ask Jacob his name before renaming him?', 'He did not know it', 'To make Jacob confess his identity as the supplanter before receiving the new name Israel', 'It was a formality', 'To test his honesty', 'b', 'Confessing his name Jacob (supplanter) preceded receiving the name Israel. See Genesis 32:27-28.'),
-- Ch33 Kids
('Genesis', 33, 'kids', 1, 'What did Esau do when he finally met Jacob?', 'He ran to meet him, embraced him, and kissed him', 'He attacked him', 'He ignored him', 'He demanded his gifts back', 'a', 'Esau ran to meet Jacob, embraced him, fell on his neck, and kissed him. See Genesis 33:4.'),
('Genesis', 33, 'kids', 2, 'Were Jacob and Esau enemies when they met again?', 'Yes, they fought', 'No, they wept together and made peace', 'Esau refused to speak', 'Jacob ran away', 'b', 'They wept together and reconciled. See Genesis 33:4.'),
('Genesis', 33, 'kids', 3, 'Where did Jacob settle after parting from Esau?', 'Egypt', 'Bethlehem', 'Shechem', 'Hebron', 'c', 'Jacob came to Shalem, a city of Shechem, and pitched his tent. See Genesis 33:18.'),
-- Ch33 Teens
('Genesis', 33, 'teens', 1, 'How did Jacob arrange his family when approaching Esau?', 'All together in one group', 'He sent them away to safety', 'He hid them all', 'Handmaids and their children first, Leah and hers next, Rachel and Joseph last', 'd', 'Jacob put the handmaids first, Leah next, and Rachel and Joseph last. See Genesis 33:2.'),
('Genesis', 33, 'teens', 2, 'How many times did Jacob bow to the ground before reaching Esau?', 'Once', 'Seven times', 'Three times', 'He did not bow', 'b', 'Jacob bowed himself to the ground seven times. See Genesis 33:3.'),
('Genesis', 33, 'teens', 3, 'Did Esau want to accept Jacob''s gifts at first?', 'Yes, eagerly', 'He demanded more', 'He accepted half', 'No, he said he had enough and Jacob had to urge him', 'd', 'Esau said "I have enough, my brother; keep that thou hast." See Genesis 33:9.'),
('Genesis', 33, 'teens', 4, 'What reason did Jacob give for not traveling with Esau to Seir?', 'The children were tender and the flocks with young would be overdriven', 'He was afraid of Esau', 'He wanted to go a different direction', 'He had business elsewhere', 'a', 'Jacob said the children were tender and the flocks nursing. See Genesis 33:13.'),
('Genesis', 33, 'teens', 5, 'What did Jacob build at Succoth?', 'An altar', 'A well', 'A house for himself and booths for his cattle', 'A wall', 'c', 'Jacob built a house and made booths for his cattle, so the place was called Succoth. See Genesis 33:17.'),
-- Ch33 Adults
('Genesis', 33, 'adults', 1, 'What remarkable comparison did Jacob make when seeing Esau''s face?', 'Like seeing an angel', 'Like seeing a brother for the first time', 'Like seeing their father Isaac', 'As though I had seen the face of God, and thou wast pleased with me', 'd', 'Jacob said seeing Esau''s face was like seeing the face of God. See Genesis 33:10.'),
('Genesis', 33, 'adults', 2, 'What word did Jacob use when referring to his gifts to Esau?', 'Tribute', 'My payment', 'My blessing that is brought to thee', 'My offering', 'c', 'Jacob called it "my blessing that is brought to thee." See Genesis 33:11.'),
('Genesis', 33, 'adults', 3, 'Where did Esau return to after the reconciliation?', 'Canaan', 'Seir', 'Haran', 'Beersheba', 'b', 'Esau returned that day on his way unto Seir. See Genesis 33:16.'),
('Genesis', 33, 'adults', 4, 'What did Jacob buy at Shechem?', 'A parcel of a field where he had spread his tent', 'A house', 'A flock of sheep', 'A well', 'a', 'Jacob bought a parcel of field from the children of Hamor. See Genesis 33:19.'),
('Genesis', 33, 'adults', 5, 'How much did Jacob pay for the field at Shechem?', 'Fifty shekels of silver', 'Ten shekels of gold', 'An hundred pieces of money', 'Two hundred pieces of silver', 'c', 'He bought it for an hundred pieces of money. See Genesis 33:19.'),
('Genesis', 33, 'adults', 6, 'What did Jacob name the altar he built at Shechem?', 'El-elohe-Israel (God, the God of Israel)', 'El-bethel', 'Jehovah-jireh', 'Ebenezer', 'a', 'He called the altar El-elohe-Israel. See Genesis 33:20.'),
('Genesis', 33, 'adults', 7, 'Jacob''s sevenfold bowing before Esau reflects what ancient custom?', 'A religious ritual', 'An Egyptian custom', 'A Canaanite greeting', 'A standard Near Eastern gesture of submission found in Amarna letters', 'd', 'Sevenfold bowing was a known Near Eastern diplomatic gesture. See Genesis 33:3.'),
('Genesis', 33, 'adults', 8, 'How does Jacob''s reconciliation with Esau parallel a larger biblical theme?', 'Justice and punishment', 'Grace, forgiveness, and reconciliation between estranged brothers', 'Judgment of the wicked', 'The conquest of enemies', 'b', 'The reunion illustrates grace and forgiveness despite past wrongs. See Genesis 33:4, 10-11.');

-- ═══ Genesis Chapters 34–35 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Ch34 Kids
('Genesis', 34, 'kids', 1, 'Who was Dinah?', 'Jacob''s daughter', 'Jacob''s wife', 'Jacob''s sister', 'Jacob''s servant', 'a', 'Dinah was the daughter of Leah and Jacob. See Genesis 34:1.'),
('Genesis', 34, 'kids', 2, 'Which two brothers took revenge for what happened to Dinah?', 'Reuben and Judah', 'Simeon and Levi', 'Dan and Naphtali', 'Gad and Asher', 'b', 'Simeon and Levi took swords and attacked the city. See Genesis 34:25.'),
('Genesis', 34, 'kids', 3, 'Was Jacob happy about what Simeon and Levi did?', 'Yes, he praised them', 'He did not find out', 'No, he was troubled and said they had made him to stink among the people of the land', 'He was indifferent', 'c', 'Jacob said "Ye have troubled me to make me to stink among the inhabitants." See Genesis 34:30.'),
-- Ch34 Teens
('Genesis', 34, 'teens', 1, 'Who was Shechem and what did he do?', 'A shepherd who befriended Jacob', 'A priest of the city', 'A merchant who traded with Jacob', 'The son of Hamor the prince who defiled Dinah', 'd', 'Shechem the son of Hamor the Hivite defiled Dinah. See Genesis 34:2.'),
('Genesis', 34, 'teens', 2, 'What condition did Jacob''s sons set before agreeing to let Shechem marry Dinah?', 'A large bride price', 'Every male in Shechem must be circumcised', 'Shechem must serve Jacob for seven years', 'Shechem must leave his city', 'b', 'They required every male to be circumcised. See Genesis 34:15.'),
('Genesis', 34, 'teens', 3, 'When did Simeon and Levi attack the city?', 'At night while they slept', 'At dawn the next morning', 'During a festival', 'On the third day when the men were sore from circumcision', 'd', 'On the third day when they were sore, Simeon and Levi came upon the city. See Genesis 34:25.'),
('Genesis', 34, 'teens', 4, 'Did Shechem genuinely love Dinah according to the text?', 'Yes, his soul clave unto Dinah and he loved the damsel', 'No, it was arranged', 'The text does not say', 'He only wanted her dowry', 'a', 'His soul clave unto Dinah and he loved the damsel. See Genesis 34:3.'),
('Genesis', 34, 'teens', 5, 'What was Jacob''s main concern about Simeon and Levi''s actions?', 'The moral wrongness', 'The loss of property', 'That the Canaanites and Perizzites would gather against him and destroy his household', 'That God would punish them', 'c', 'Jacob feared the surrounding peoples would destroy him. See Genesis 34:30.'),
-- Ch34 Adults
('Genesis', 34, 'adults', 1, 'What title is given to Hamor in this chapter?', 'King of Shechem', 'Chief priest', 'Judge of the land', 'The Hivite, prince of the country', 'd', 'Hamor is called the Hivite, prince of the country. See Genesis 34:2.'),
('Genesis', 34, 'adults', 2, 'What economic incentive did Hamor offer Jacob''s family?', 'Gold and silver', 'Free livestock', 'Trade, dwell, and get possessions in the land', 'A palace to live in', 'c', 'Hamor proposed they trade, dwell, and get possessions. See Genesis 34:10.'),
('Genesis', 34, 'adults', 3, 'What did Shechem offer as bride price for Dinah?', 'One hundred pieces of silver', 'Ask me never so much dowry and gift, and I will give according as ye shall say', 'His father''s inheritance', 'Half of his lands', 'b', 'Shechem said "Ask me never so much dowry and gift." See Genesis 34:12.'),
('Genesis', 34, 'adults', 4, 'The text says Jacob''s sons answered Shechem and Hamor how?', 'Deceitfully, because Shechem had defiled Dinah their sister', 'Honestly', 'With respect', 'With silence', 'a', 'The sons of Jacob answered Shechem and Hamor deceitfully. See Genesis 34:13.'),
('Genesis', 34, 'adults', 5, 'What argument did Hamor and Shechem use to persuade their own city''s men to be circumcised?', 'Religious duty', 'Military alliance', 'Shall not their cattle and substance and every beast of theirs be ours', 'To honor the God of Jacob', 'c', 'They told the men Jacob''s wealth would become theirs. See Genesis 34:23.'),
('Genesis', 34, 'adults', 6, 'Besides killing the men, what else did Jacob''s sons do to the city?', 'They took the sheep, oxen, asses, wealth, children, and wives as spoil', 'Nothing else', 'They burned the city', 'They tore down the walls', 'a', 'They took all their wealth, little ones, and wives as spoil. See Genesis 34:28-29.'),
('Genesis', 34, 'adults', 7, 'How did Simeon and Levi justify their actions?', 'They claimed divine command', 'They blamed Jacob for inaction', 'They denied responsibility', 'They said should he deal with our sister as with an harlot', 'd', 'They responded "Should he deal with our sister as with an harlot?" See Genesis 34:31.'),
('Genesis', 34, 'adults', 8, 'Jacob later referenced this event in his deathbed blessing. What did he say about Simeon and Levi?', 'He praised their valor', 'He cursed their anger and wrath, saying he would divide and scatter them in Israel', 'He forgave them fully', 'He gave them double portions', 'b', 'Jacob cursed their fierce anger in Genesis 49:5-7, connecting to this event.'),
-- Ch35 Kids
('Genesis', 35, 'kids', 1, 'Where did God tell Jacob to go and build an altar?', 'Bethel', 'Jerusalem', 'Shechem', 'Egypt', 'a', 'God said unto Jacob "Arise, go up to Bethel, and make there an altar." See Genesis 35:1.'),
('Genesis', 35, 'kids', 2, 'What was the name of Rachel''s second son, born in this chapter?', 'Joseph', 'Benjamin', 'Judah', 'Dan', 'b', 'Rachel bore a son and named him Benjamin. See Genesis 35:18.'),
('Genesis', 35, 'kids', 3, 'What happened to Rachel in this chapter?', 'She moved to Egypt', 'She went back to Laban', 'She died giving birth to Benjamin', 'She became ill but recovered', 'c', 'Rachel died in childbirth and was buried on the way to Ephrath. See Genesis 35:19.'),
-- Ch35 Teens
('Genesis', 35, 'teens', 1, 'What did Jacob tell his household to do before going to Bethel?', 'Gather all their wealth', 'Build new tents', 'Fast for three days', 'Put away the strange gods, be clean, and change their garments', 'd', 'Jacob told them to put away strange gods and be clean. See Genesis 35:2.'),
('Genesis', 35, 'teens', 2, 'What did Jacob do with the strange gods and earrings his family gave him?', 'He destroyed them in fire', 'He hid them under the oak tree at Shechem', 'He threw them in a river', 'He kept them hidden', 'b', 'Jacob hid them under the oak which was by Shechem. See Genesis 35:4.'),
('Genesis', 35, 'teens', 3, 'What name did Rachel give her son before she died?', 'Benjamin', 'Reuben', 'Joseph', 'Benoni, meaning son of my sorrow', 'd', 'Rachel called him Ben-oni but Jacob named him Benjamin. See Genesis 35:18.'),
('Genesis', 35, 'teens', 4, 'How old was Isaac when he died?', 'One hundred and eighty years', 'One hundred and fifty years', 'One hundred and sixty years', 'Two hundred years', 'a', 'Isaac was an hundred and fourscore (180) years old when he died. See Genesis 35:28.'),
('Genesis', 35, 'teens', 5, 'Who buried Isaac?', 'Jacob alone', 'The servants', 'Esau and Jacob together', 'The men of Hebron', 'c', 'His sons Esau and Jacob buried him. See Genesis 35:29.'),
-- Ch35 Adults
('Genesis', 35, 'adults', 1, 'What supernatural protection did God provide Jacob on the journey to Bethel?', 'An angel guard', 'Invisibility', 'A pillar of fire', 'The terror of God was upon the cities round about so they did not pursue Jacob''s sons', 'd', 'The terror of God fell on surrounding cities so they did not pursue. See Genesis 35:5.'),
('Genesis', 35, 'adults', 2, 'What name did God give the place at Bethel where He spoke to Jacob?', 'Bethel only', 'Peniel', 'El-bethel, the God of Bethel', 'Gilgal', 'c', 'Jacob called the place El-bethel. See Genesis 35:7.'),
('Genesis', 35, 'adults', 3, 'Who died and was buried beneath the oak below Bethel?', 'Rachel', 'Deborah, Rebekah''s nurse', 'Leah', 'Zilpah', 'b', 'Deborah, Rebekah''s nurse, died and was buried below Bethel. See Genesis 35:8.'),
('Genesis', 35, 'adults', 4, 'God reaffirmed to Jacob at Bethel that his name was now Israel. What additional promise was given?', 'A nation and a company of nations shall come from thee, and kings shall come out of thy loins', 'Wealth beyond measure', 'Victory over all enemies', 'A thousand years of peace', 'a', 'God promised nations and kings from Jacob''s line. See Genesis 35:11.'),
('Genesis', 35, 'adults', 5, 'What does Benjamin mean, as named by Jacob?', 'Son of my sorrow', 'Son of strength', 'Son of the right hand', 'Youngest son', 'c', 'Benjamin means son of the right hand. See Genesis 35:18.'),
('Genesis', 35, 'adults', 6, 'What sin did Reuben commit in this chapter?', 'He lay with Bilhah his father''s concubine, and Israel heard of it', 'He stole from Jacob', 'He worshipped idols', 'He struck his brother', 'a', 'Reuben lay with Bilhah, and Israel heard it. See Genesis 35:22.'),
('Genesis', 35, 'adults', 7, 'How many sons of Jacob are listed in 35:23-26, and which mothers bore them?', 'Ten sons by two mothers', 'Twelve sons by two mothers', 'Eleven sons by three mothers', 'Twelve sons by four mothers: Leah (6), Rachel (2), Bilhah (2), Zilpah (2)', 'd', 'Twelve sons are listed from Leah, Rachel, Bilhah, and Zilpah. See Genesis 35:23-26.'),
('Genesis', 35, 'adults', 8, 'Where was Rachel buried?', 'At Machpelah', 'In the way to Ephrath, which is Bethlehem', 'At Bethel', 'At Shechem', 'b', 'Rachel was buried in the way to Ephrath, which is Bethlehem. See Genesis 35:19.');

-- ═══ Genesis Chapters 36–37 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Ch36 Kids
('Genesis', 36, 'kids', 1, 'Whose family line is described in Genesis 36?', 'Esau''s', 'Jacob''s', 'Abraham''s', 'Isaac''s', 'a', 'Genesis 36 records the generations of Esau, who is Edom. See Genesis 36:1.'),
('Genesis', 36, 'kids', 2, 'What other name is Esau known by?', 'Israel', 'Edom', 'Moab', 'Ammon', 'b', 'Esau is also called Edom. See Genesis 36:1.'),
('Genesis', 36, 'kids', 3, 'Why did Esau move away from Jacob?', 'They had a fight', 'Jacob sent him away', 'Their riches were too great for them to dwell together', 'God told Esau to leave', 'c', 'Their substance was too great for them to dwell together. See Genesis 36:7.'),
-- Ch36 Teens
('Genesis', 36, 'teens', 1, 'Where did Esau settle?', 'Canaan', 'Haran', 'Egypt', 'Mount Seir', 'd', 'Esau dwelt in mount Seir. See Genesis 36:8.'),
('Genesis', 36, 'teens', 2, 'What type of leaders came from Esau''s line?', 'Prophets', 'Dukes (chiefs) and kings', 'Priests', 'Judges', 'b', 'The chapter lists dukes and kings that reigned in Edom. See Genesis 36:15-19, 31-39.'),
('Genesis', 36, 'teens', 3, 'What is significant about Edom having kings before Israel?', 'Esau was more blessed', 'Nothing significant', 'Edom was conquered first', 'Kings reigned in Edom before there reigned any king over the children of Israel', 'd', 'These are the kings that reigned in Edom before any king reigned over Israel. See Genesis 36:31.'),
('Genesis', 36, 'teens', 4, 'Who was Eliphaz in relation to Esau?', 'His firstborn son', 'His brother', 'His nephew', 'His servant', 'a', 'Eliphaz was the son of Esau''s wife Adah. See Genesis 36:10.'),
('Genesis', 36, 'teens', 5, 'Who was Amalek in relation to Esau?', 'His brother', 'His uncle', 'His grandson through Eliphaz and his concubine Timna', 'His servant', 'c', 'Amalek was the son of Eliphaz by Timna. See Genesis 36:12.'),
-- Ch36 Adults
('Genesis', 36, 'adults', 1, 'How many dukes (chiefs) of Esau are listed in Genesis 36:40-43?', 'Seven', 'Twenty', 'Fourteen', 'Eleven', 'd', 'Eleven dukes are listed in verses 40-43. See Genesis 36:40-43.'),
('Genesis', 36, 'adults', 2, 'Who were the Horites mentioned in this chapter?', 'Descendants of Abraham', 'Egyptian settlers', 'The original inhabitants of Seir whom Esau''s descendants displaced', 'Canaanite traders', 'c', 'The Horites were the earlier inhabitants of Seir. See Genesis 36:20-21.'),
('Genesis', 36, 'adults', 3, 'What is Anah remembered for in Genesis 36:24?', 'Defeating the Horites', 'Finding the mules (hot springs) in the wilderness as he fed his father''s asses', 'Building a city', 'Discovering gold', 'b', 'Anah found the mules in the wilderness while feeding Zibeon''s asses. See Genesis 36:24.'),
('Genesis', 36, 'adults', 4, 'Which of Esau''s wives was the daughter of Ishmael?', 'Bashemath', 'Adah', 'Aholibamah', 'Judith', 'a', 'Bashemath was Ishmael''s daughter. See Genesis 36:3.'),
('Genesis', 36, 'adults', 5, 'What nation would later descend from Amalek and become a persistent enemy of Israel?', 'The Philistines', 'The Moabites', 'The Amalekites', 'The Ammonites', 'c', 'Amalek fathered the Amalekites, perpetual enemies of Israel. See Genesis 36:12 and Exodus 17:8-16.'),
('Genesis', 36, 'adults', 6, 'How does Genesis 36 structurally function in the narrative?', 'It closes out Esau''s line before shifting focus entirely to Jacob and Joseph', 'It introduces a new storyline', 'It provides a genealogy of Israel', 'It describes the conquest of Canaan', 'a', 'The chapter concludes Esau''s account before the Joseph narrative begins in chapter 37.'),
('Genesis', 36, 'adults', 7, 'Who was Oholibamah the daughter of?', 'Ishmael', 'Beeri', 'Heth', 'Anah the daughter of Zibeon the Hivite', 'd', 'Aholibamah was the daughter of Anah, the daughter of Zibeon. See Genesis 36:2.'),
('Genesis', 36, 'adults', 8, 'What is the theological significance of recording Edom''s prosperity alongside Israel''s story?', 'To show Edom was superior', 'To show God blessed Esau materially as well, fulfilling Isaac''s blessing, even though the covenant line went through Jacob', 'To contrast good and evil', 'No significance', 'b', 'Esau prospered as Isaac blessed, but the covenant continued through Jacob. See Genesis 27:39-40 and 36:1-43.'),
-- Ch37 Kids
('Genesis', 37, 'kids', 1, 'What special gift did Jacob give to Joseph?', 'A coat of many colours', 'A golden ring', 'A new pair of sandals', 'A silver crown', 'a', 'Israel made Joseph a coat of many colours. See Genesis 37:3.'),
('Genesis', 37, 'kids', 2, 'What did Joseph dream about?', 'Flying through the sky', 'Sheaves of grain bowing down to his sheaf, and the sun, moon, and stars bowing to him', 'A ladder to heaven', 'A burning bush', 'b', 'Joseph dreamed of sheaves bowing and sun, moon, and stars bowing. See Genesis 37:7-9.'),
('Genesis', 37, 'kids', 3, 'What did Joseph''s brothers do to him?', 'They gave him a gift', 'They sent him to school', 'They sold him to merchants going to Egypt', 'They made him a shepherd', 'c', 'The brothers sold Joseph to Ishmaelites for twenty pieces of silver. See Genesis 37:28.'),
-- Ch37 Teens
('Genesis', 37, 'teens', 1, 'Why did Joseph''s brothers hate him?', 'He was lazy', 'He was unkind', 'He stole from them', 'Their father loved Joseph more than them and Joseph had dreams of ruling over them', 'd', 'They hated him because of the coat and his dreams. See Genesis 37:4, 8.'),
('Genesis', 37, 'teens', 2, 'How old was Joseph when he was sold into slavery?', 'Twelve years old', 'Seventeen years old', 'Twenty years old', 'Fifteen years old', 'b', 'Joseph was seventeen years old. See Genesis 37:2.'),
('Genesis', 37, 'teens', 3, 'Which brother tried to save Joseph from being killed?', 'Judah', 'Levi', 'Simeon', 'Reuben', 'd', 'Reuben said to shed no blood but cast him into a pit, intending to rescue him later. See Genesis 37:21-22.'),
('Genesis', 37, 'teens', 4, 'How much was Joseph sold for?', 'Twenty pieces of silver', 'Thirty pieces of silver', 'Ten pieces of gold', 'Fifty pieces of silver', 'a', 'They sold Joseph for twenty pieces of silver. See Genesis 37:28.'),
('Genesis', 37, 'teens', 5, 'What did the brothers tell Jacob had happened to Joseph?', 'Joseph ran away', 'Joseph drowned in a river', 'They showed him the coat dipped in goat''s blood and said a wild beast must have killed him', 'Joseph was kidnapped by strangers', 'c', 'They dipped the coat in goat blood and brought it to Jacob. See Genesis 37:31-33.'),
-- Ch37 Adults
('Genesis', 37, 'adults', 1, 'What did Joseph bring to his father about his brothers?', 'A gift', 'A request to leave', 'A peace offering', 'An evil report of them', 'd', 'Joseph brought unto his father their evil report. See Genesis 37:2.'),
('Genesis', 37, 'adults', 2, 'In Joseph''s second dream, what represented his father, mother, and brothers?', 'Twelve stars only', 'Twelve sheaves of grain', 'The sun, moon, and eleven stars', 'Mountains and rivers', 'c', 'The sun, moon, and eleven stars bowed to Joseph. See Genesis 37:9.'),
('Genesis', 37, 'adults', 3, 'How did Jacob respond to Joseph''s second dream?', 'He ignored it', 'He rebuked Joseph but observed (kept) the saying', 'He praised Joseph publicly', 'He told him to stop dreaming', 'b', 'His father rebuked him but observed the saying. See Genesis 37:10-11.'),
('Genesis', 37, 'adults', 4, 'Where were the brothers pasturing when Joseph was sent to find them?', 'Shechem, then Dothan', 'Bethel', 'Hebron', 'Beersheba', 'a', 'They went from Shechem to Dothan. See Genesis 37:12-17.'),
('Genesis', 37, 'adults', 5, 'Which brother suggested selling Joseph rather than killing him?', 'Reuben', 'Simeon', 'Judah', 'Levi', 'c', 'Judah said "What profit is it if we slay our brother?" See Genesis 37:26.'),
('Genesis', 37, 'adults', 6, 'Who were the merchants that bought Joseph?', 'Ishmaelites, also called Midianites', 'Egyptians', 'Philistines', 'Moabites', 'a', 'Ishmaelite/Midianite merchantmen bought Joseph. See Genesis 37:28.'),
('Genesis', 37, 'adults', 7, 'To whom was Joseph sold in Egypt?', 'Pharaoh directly', 'A wealthy merchant', 'The prison keeper', 'Potiphar, an officer of Pharaoh and captain of the guard', 'd', 'The Midianites sold Joseph to Potiphar in Egypt. See Genesis 37:36.'),
('Genesis', 37, 'adults', 8, 'How does the selling of Joseph for twenty pieces of silver prefigure a later biblical event?', 'Moses'' birth', 'Christ was betrayed for thirty pieces of silver, both involving jealousy and the selling of a chosen one', 'David''s anointing', 'The Exodus', 'b', 'Joseph sold for silver by jealous brothers parallels Christ''s betrayal. See Genesis 37:28 and Matthew 26:15.');

-- ═══ Genesis Chapters 38–42 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Ch38 Kids
('Genesis', 38, 'kids', 1, 'Which of Jacob''s sons is the main person in Genesis 38?', 'Judah', 'Joseph', 'Reuben', 'Benjamin', 'a', 'Genesis 38 tells the story of Judah and his family. See Genesis 38:1.'),
('Genesis', 38, 'kids', 2, 'How many sons did Judah have at the start of this chapter?', 'One', 'Three', 'Two', 'Four', 'b', 'Judah had three sons: Er, Onan, and Shelah. See Genesis 38:3-5.'),
('Genesis', 38, 'kids', 3, 'What were the names of the twin boys born at the end of this chapter?', 'Jacob and Esau', 'Manasseh and Ephraim', 'Pharez and Zarah', 'Simeon and Levi', 'c', 'The twins were Pharez (Perez) and Zarah (Zerah). See Genesis 38:29-30.'),
-- Ch38 Teens
('Genesis', 38, 'teens', 1, 'Why did Er, Judah''s firstborn, die?', 'He was killed in battle', 'He had an accident', 'He died of illness', 'He was wicked in the sight of the LORD and the LORD slew him', 'd', 'Er was wicked in the sight of the LORD, and the LORD slew him. See Genesis 38:7.'),
('Genesis', 38, 'teens', 2, 'Why was Onan supposed to marry Tamar?', 'He loved her', 'To raise up seed for his deceased brother Er as was the custom', 'Judah forced him', 'She chose Onan herself', 'b', 'Judah told Onan to marry Tamar to raise up seed for Er. See Genesis 38:8.'),
('Genesis', 38, 'teens', 3, 'Why did Judah not give his son Shelah to Tamar?', 'Shelah was too young', 'Shelah was already married', 'Tamar refused Shelah', 'He was afraid Shelah would also die like his brothers', 'd', 'Judah feared lest Shelah die also, as his brethren did. See Genesis 38:11.'),
('Genesis', 38, 'teens', 4, 'How did Tamar get Judah to notice her?', 'She disguised herself with a veil and sat by the road', 'She sent him a letter', 'She came to his house', 'She asked a friend to introduce them', 'a', 'Tamar covered herself with a veil and sat in an open place. See Genesis 38:14.'),
('Genesis', 38, 'teens', 5, 'What happened during the birth of the twins?', 'Both came out together', 'Pharez was much larger', 'Zarah put out his hand first with a scarlet thread, but Pharez broke forth first', 'They were born days apart', 'c', 'Zarah''s hand came first but Pharez actually broke forth first. See Genesis 38:28-30.'),
-- Ch38 Adults
('Genesis', 38, 'adults', 1, 'What three items did Tamar request as a pledge from Judah?', 'Gold, silver, and a ring', 'His ring, sword, and shield', 'His cloak, sandals, and belt', 'His signet, bracelets, and staff', 'd', 'Tamar asked for his signet, bracelets, and staff. See Genesis 38:18.'),
('Genesis', 38, 'adults', 2, 'What was Judah''s initial reaction when told Tamar was pregnant?', 'He was pleased', 'He ignored the news', 'He said bring her forth and let her be burnt', 'He asked who the father was', 'c', 'Judah said "Bring her forth, and let her be burnt." See Genesis 38:24.'),
('Genesis', 38, 'adults', 3, 'How did Tamar prove Judah was the father?', 'She brought witnesses', 'She sent the signet, bracelets, and staff saying the owner of these is the father', 'She told everyone publicly', 'A servant testified', 'b', 'Tamar sent the pledged items to Judah for identification. See Genesis 38:25.'),
('Genesis', 38, 'adults', 4, 'What did Judah confess when confronted with the evidence?', 'She hath been more righteous than I because I gave her not to Shelah my son', 'He denied everything', 'He blamed Tamar', 'He said nothing', 'a', 'Judah admitted Tamar was more righteous than he. See Genesis 38:26.'),
('Genesis', 38, 'adults', 5, 'Why is Pharez significant in biblical genealogy?', 'He became a king', 'He was the firstborn of all Jacob''s grandchildren', 'He is in the lineage of David and ultimately Jesus Christ', 'He founded a tribe', 'c', 'Pharez appears in the genealogy of David and Christ. See Ruth 4:18-22 and Matthew 1:3.'),
('Genesis', 38, 'adults', 6, 'Who was Judah''s wife and what was her background?', 'The daughter of Shuah, a Canaanite', 'Tamar, an Israelite', 'Asenath, an Egyptian', 'Zipporah, a Midianite', 'a', 'Judah married the daughter of a certain Canaanite named Shuah. See Genesis 38:2.'),
('Genesis', 38, 'adults', 7, 'Who did Judah send to retrieve his pledge from the woman by the road?', 'His brother Simeon', 'His son Shelah', 'His servant', 'Hirah the Adullamite, his friend', 'd', 'Judah sent his friend Hirah the Adullamite. See Genesis 38:20.'),
('Genesis', 38, 'adults', 8, 'Why does this chapter interrupt the Joseph narrative between chapters 37 and 39?', 'It was misplaced by scribes', 'It contrasts Judah''s moral failure in Canaan with Joseph''s integrity in Egypt and establishes the Messianic line through Pharez', 'It has no connection to the surrounding text', 'It was added later by editors', 'b', 'The chapter contrasts Judah with Joseph and establishes the line to David and Christ.'),
-- Ch39 Kids
('Genesis', 39, 'kids', 1, 'Who bought Joseph as a slave in Egypt?', 'Potiphar', 'Pharaoh', 'The baker', 'The butler', 'a', 'Joseph was bought by Potiphar, an officer of Pharaoh. See Genesis 39:1.'),
('Genesis', 39, 'kids', 2, 'Was God with Joseph in Egypt?', 'No, God forgot about him', 'Yes, the LORD was with Joseph and made everything he did successful', 'Joseph was on his own', 'Only sometimes', 'b', 'The LORD was with Joseph and he was a prosperous man. See Genesis 39:2.'),
('Genesis', 39, 'kids', 3, 'What happened to Joseph at the end of this chapter?', 'He became Pharaoh''s advisor', 'He returned home', 'He was put in prison', 'He became a merchant', 'c', 'Joseph''s master put him into the prison. See Genesis 39:20.'),
-- Ch39 Teens
('Genesis', 39, 'teens', 1, 'What position did Potiphar give Joseph in his household?', 'Cook', 'Guard', 'Gardener', 'Overseer of all that he had', 'd', 'Potiphar made Joseph overseer over his house and all that he had. See Genesis 39:4-5.'),
('Genesis', 39, 'teens', 2, 'What did Potiphar''s wife repeatedly ask Joseph to do?', 'Leave the house', 'Lie with her', 'Steal from Potiphar', 'Run away with her', 'b', 'Potiphar''s wife said to Joseph "Lie with me." See Genesis 39:7.'),
('Genesis', 39, 'teens', 3, 'What reason did Joseph give for refusing?', 'He was afraid of Potiphar', 'He was too busy with work', 'He did not care for her', 'How can I do this great wickedness and sin against God', 'd', 'Joseph said "how then can I do this great wickedness, and sin against God?" See Genesis 39:9.'),
('Genesis', 39, 'teens', 4, 'What did Potiphar''s wife use as false evidence against Joseph?', 'His garment that he left behind when he fled', 'A letter', 'A stolen item', 'A witness she bribed', 'a', 'She kept his garment and showed it as evidence. See Genesis 39:12-18.'),
('Genesis', 39, 'teens', 5, 'Even in prison, how did God show favour to Joseph?', 'He sent an angel to free him', 'God made the walls fall', 'The LORD gave him favour with the keeper of the prison who committed everything to his hand', 'Joseph bribed his way out', 'c', 'The LORD gave Joseph favour with the prison keeper. See Genesis 39:21-23.'),
-- Ch39 Adults
('Genesis', 39, 'adults', 1, 'How is Joseph physically described in this chapter?', 'Strong and tall', 'No description is given', 'Average looking', 'A goodly person and well favoured', 'd', 'Joseph was a goodly person, and well favoured. See Genesis 39:6.'),
('Genesis', 39, 'adults', 2, 'What comprehensive reason did Joseph give for refusing Potiphar''s wife?', 'Fear of punishment only', 'Cultural propriety', 'His master trusted him with everything except his wife and it would be wickedness and sin against God', 'He had taken a vow', 'c', 'Joseph cited his master''s trust and that it would be sin against God. See Genesis 39:8-9.'),
('Genesis', 39, 'adults', 3, 'How did God bless Potiphar''s house because of Joseph?', 'With military victories', 'The blessing of the LORD was upon all that he had in the house and in the field', 'With political power', 'With many children', 'b', 'The LORD blessed the Egyptian''s house for Joseph''s sake. See Genesis 39:5.'),
('Genesis', 39, 'adults', 4, 'What role did Joseph assume in the prison?', 'The keeper committed all the prisoners to Joseph''s hand and whatever was done there he was the doer of it', 'He planned escapes', 'He served food only', 'He kept records', 'a', 'The prison keeper committed everything to Joseph''s hand. See Genesis 39:22.'),
('Genesis', 39, 'adults', 5, 'What pattern is established by Joseph prospering in both Potiphar''s house and prison?', 'Joseph was simply lucky', 'Joseph was a skilled negotiator', 'Wherever Joseph went the LORD was with him and made all that he did to prosper', 'Others took pity on him', 'c', 'The LORD was with Joseph and prospered him in both settings. See Genesis 39:2-3, 21-23.'),
('Genesis', 39, 'adults', 6, 'How persistent was Potiphar''s wife in her temptation?', 'She spake to Joseph day by day but he hearkened not unto her', 'She asked only once', 'She tried twice then gave up', 'She sent others to persuade him', 'a', 'She spoke to Joseph day by day. See Genesis 39:10.'),
('Genesis', 39, 'adults', 7, 'What accusation did Potiphar''s wife make to the men of the house?', 'That Joseph stole valuables', 'That Joseph worshipped foreign gods', 'That Joseph tried to flee', 'That her husband brought in a Hebrew to mock us', 'd', 'She said her husband brought in a Hebrew to mock them. See Genesis 39:14.'),
('Genesis', 39, 'adults', 8, 'How does Joseph''s unjust imprisonment serve the larger divine plan?', 'It was mere coincidence', 'It placed Joseph in the same prison as Pharaoh''s butler and baker, setting up his rise to power', 'It taught Joseph humility only', 'It had no larger purpose', 'b', 'Prison positioned Joseph to meet Pharaoh''s servants and interpret dreams. See Genesis 39:20 and chapters 40-41.'),
-- Ch40 Kids
('Genesis', 40, 'kids', 1, 'Who else was in prison with Joseph?', 'Pharaoh''s butler and baker', 'Two soldiers', 'Two shepherds', 'Two merchants', 'a', 'Pharaoh''s butler and baker were put in the prison with Joseph. See Genesis 40:1-3.'),
('Genesis', 40, 'kids', 2, 'What special ability did God give Joseph in prison?', 'Super strength', 'The ability to understand the meaning of dreams', 'The power to escape', 'The gift of singing', 'b', 'Joseph said "Do not interpretations belong to God?" and interpreted their dreams. See Genesis 40:8.'),
('Genesis', 40, 'kids', 3, 'What happened to the butler after Joseph interpreted his dream?', 'He stayed in prison', 'He was punished', 'He was restored to his position serving Pharaoh', 'He ran away', 'c', 'The chief butler was restored unto his butlership. See Genesis 40:21.'),
-- Ch40 Teens
('Genesis', 40, 'teens', 1, 'What did the butler dream about?', 'Seven fat cows', 'Sheaves of wheat', 'A ladder to heaven', 'A vine with three branches that budded, blossomed, and produced ripe grapes which he pressed into Pharaoh''s cup', 'd', 'The butler dreamed of a vine with three branches and grapes pressed into Pharaoh''s cup. See Genesis 40:9-11.'),
('Genesis', 40, 'teens', 2, 'What did the baker dream about?', 'Seven ears of corn', 'Three white baskets on his head with baked goods that birds ate from the top basket', 'A river of bread', 'A great oven', 'b', 'The baker dreamed of three baskets with birds eating from the top one. See Genesis 40:16-17.'),
('Genesis', 40, 'teens', 3, 'What did the three branches and three baskets represent?', 'Three months', 'Three weeks', 'Three years', 'Three days', 'd', 'Both sets of three represented three days. See Genesis 40:12-13, 18-19.'),
('Genesis', 40, 'teens', 4, 'What happened to the baker?', 'Pharaoh hanged him, as Joseph had interpreted', 'He was restored to his job', 'He escaped from prison', 'He was sent to another land', 'a', 'The chief baker was hanged as Joseph had interpreted. See Genesis 40:22.'),
('Genesis', 40, 'teens', 5, 'What favour did Joseph ask of the butler?', 'To send him money', 'To bring him food', 'To remember him and mention him to Pharaoh so he could get out of prison', 'To send a message to his family', 'c', 'Joseph asked the butler to think on him and make mention to Pharaoh. See Genesis 40:14.'),
-- Ch40 Adults
('Genesis', 40, 'adults', 1, 'What did Joseph say about the source of dream interpretation?', 'It came from his own wisdom', 'He read it in scrolls', 'He learned it from the Egyptians', 'Do not interpretations belong to God? Tell me your dreams', 'd', 'Joseph said "Do not interpretations belong to God?" See Genesis 40:8.'),
('Genesis', 40, 'adults', 2, 'What detail did Joseph share about his own background when speaking to the butler?', 'That he was wealthy', 'That he was a prince', 'That he was stolen away out of the land of the Hebrews and had done nothing to deserve the dungeon', 'That he had prophetic powers', 'c', 'Joseph said he was stolen from the land of the Hebrews. See Genesis 40:15.'),
('Genesis', 40, 'adults', 3, 'What occasion prompted the butler and baker''s release from prison?', 'A general amnesty', 'Pharaoh''s birthday', 'A religious festival', 'A military victory', 'b', 'The third day was Pharaoh''s birthday and he made a feast. See Genesis 40:20.'),
('Genesis', 40, 'adults', 4, 'What did the chief butler fail to do after being restored?', 'He did not remember Joseph but forgat him', 'Pay Joseph', 'Thank Pharaoh', 'Return to prison to help others', 'a', 'The chief butler did not remember Joseph, but forgat him. See Genesis 40:23.'),
('Genesis', 40, 'adults', 5, 'Why did the baker decide to share his dream with Joseph?', 'He was forced to', 'Joseph asked him', 'He saw that the interpretation of the butler''s dream was good', 'The butler urged him', 'c', 'When the chief baker saw that the interpretation was good, he shared his dream. See Genesis 40:16.'),
('Genesis', 40, 'adults', 6, 'What specific detail of the baker''s dream foretold his death?', 'The birds did eat them out of the basket upon his head, meaning Pharaoh would hang him and birds would eat his flesh', 'Empty baskets', 'Broken bread', 'Overturned baskets', 'a', 'Birds eating from the top basket symbolized birds eating his flesh. See Genesis 40:17-19.'),
('Genesis', 40, 'adults', 7, 'How long did Joseph remain in prison after the butler was restored before the events of chapter 41?', 'One month', 'Three years', 'Six months', 'Two full years', 'd', 'At the end of two full years Pharaoh dreamed. See Genesis 41:1.'),
('Genesis', 40, 'adults', 8, 'How does the butler''s forgetfulness serve the narrative theologically?', 'It shows human unreliability only', 'It demonstrates that Joseph''s deliverance would come from God''s timing through Pharaoh''s dreams, not through human favour', 'It was accidental', 'It had no deeper meaning', 'b', 'God''s timing ensured Joseph''s release would coincide with Egypt''s crisis. See Genesis 40:23 and 41:1.'),
-- Ch41 Kids
('Genesis', 41, 'kids', 1, 'What did Pharaoh dream about?', 'Seven fat cows eaten by seven thin cows, and seven good ears of corn eaten by seven thin ears', 'A coat of many colours', 'A ladder reaching to heaven', 'Twelve stars bowing down', 'a', 'Pharaoh dreamed of seven fat cows, seven thin cows, seven good ears, and seven thin ears. See Genesis 41:1-7.'),
('Genesis', 41, 'kids', 2, 'Who told Pharaoh that Joseph could interpret dreams?', 'A soldier', 'The chief butler', 'The baker', 'Moses', 'b', 'The chief butler finally remembered Joseph and told Pharaoh. See Genesis 41:9-13.'),
('Genesis', 41, 'kids', 3, 'What important job did Pharaoh give to Joseph?', 'Head cook', 'Captain of the army', 'Ruler over all the land of Egypt', 'Builder of pyramids', 'c', 'Pharaoh set Joseph over all the land of Egypt. See Genesis 41:41.'),
-- Ch41 Teens
('Genesis', 41, 'teens', 1, 'What did the seven fat cows and seven good ears of corn represent?', 'Seven great kings', 'Seven rivers of blessing', 'Seven victories in war', 'Seven years of great plenty in Egypt', 'd', 'The seven good cows and ears were seven years of plenty. See Genesis 41:29.'),
('Genesis', 41, 'teens', 2, 'What did the seven thin cows and seven thin ears represent?', 'Seven weak enemies', 'Seven years of famine that would follow the plenty', 'Seven droughts', 'Seven plagues', 'b', 'The seven lean cows and thin ears were seven years of famine. See Genesis 41:30.'),
('Genesis', 41, 'teens', 3, 'What plan did Joseph recommend to Pharaoh?', 'Build an army', 'Pray for rain', 'Move to another land', 'Appoint a wise man to store one fifth of the harvest during the seven good years', 'd', 'Joseph advised storing a fifth of the produce during the plentiful years. See Genesis 41:33-36.'),
('Genesis', 41, 'teens', 4, 'What Egyptian name did Pharaoh give Joseph?', 'Zaphnath-paaneah', 'Imhotep', 'Amenhotep', 'Rameses', 'a', 'Pharaoh called Joseph Zaphnath-paaneah. See Genesis 41:45.'),
('Genesis', 41, 'teens', 5, 'How old was Joseph when he stood before Pharaoh?', 'Twenty years old', 'Twenty-five years old', 'Thirty years old', 'Thirty-five years old', 'c', 'Joseph was thirty years old when he stood before Pharaoh. See Genesis 41:46.'),
-- Ch41 Adults
('Genesis', 41, 'adults', 1, 'What did Joseph say to Pharaoh about who interprets dreams?', 'Joseph took credit', 'He attributed it to Egyptian learning', 'He said it was a natural ability', 'It is not in me; God shall give Pharaoh an answer of peace', 'd', 'Joseph said "It is not in me: God shall give Pharaoh an answer of peace." See Genesis 41:16.'),
('Genesis', 41, 'adults', 2, 'Why did Pharaoh say the dream was doubled (shown twice)?', 'For emphasis only', 'It was a coincidence', 'Because the thing is established by God and God will shortly bring it to pass', 'To confuse his magicians', 'c', 'Joseph explained the dream was doubled because it was established by God. See Genesis 41:32.'),
('Genesis', 41, 'adults', 3, 'What symbols of authority did Pharaoh give Joseph?', 'A crown and scepter', 'His ring, vestures of fine linen, and a gold chain about his neck', 'A chariot only', 'A palace and servants', 'b', 'Pharaoh gave Joseph his ring, fine linen, and a gold chain. See Genesis 41:42.'),
('Genesis', 41, 'adults', 4, 'Who was Joseph''s wife and who was her father?', 'Asenath, daughter of Potipherah priest of On', 'An Israelite woman', 'A Midianite woman', 'Zipporah, daughter of Jethro', 'a', 'Pharaoh gave Joseph Asenath the daughter of Poti-pherah priest of On. See Genesis 41:45.'),
('Genesis', 41, 'adults', 5, 'What were the names of Joseph''s two sons and what did their names mean?', 'Reuben and Simeon', 'Perez and Zerah', 'Manasseh (God made me forget my toil) and Ephraim (God hath caused me to be fruitful)', 'Gershom and Eliezer', 'c', 'Manasseh means forgetting and Ephraim means fruitful. See Genesis 41:51-52.'),
('Genesis', 41, 'adults', 6, 'How extensive was the famine according to the text?', 'The famine was over all the face of the earth and all countries came to Egypt to buy corn', 'Only in Egypt', 'Only in Canaan', 'In Egypt and Canaan only', 'a', 'The famine was in all lands and all countries came to Joseph. See Genesis 41:56-57.'),
('Genesis', 41, 'adults', 7, 'What did the people cry to Pharaoh when the famine began?', 'Save us from death', 'They rioted', 'They demanded bread', 'Pharaoh told them to go unto Joseph and do whatever he said', 'd', 'Pharaoh said "Go unto Joseph; what he saith to you, do." See Genesis 41:55.'),
('Genesis', 41, 'adults', 8, 'What was proclaimed before Joseph''s chariot as he rode through Egypt?', 'Make way for the prince', 'Bow the knee (Abrech)', 'Hail to the king', 'Long live Joseph', 'b', 'They cried before him "Bow the knee" (Abrech). See Genesis 41:43.'),
-- Ch42 Kids
('Genesis', 42, 'kids', 1, 'Why did Joseph''s brothers go to Egypt?', 'To buy grain because there was a famine', 'To visit Joseph', 'To trade animals', 'To find new homes', 'a', 'Jacob sent his sons to Egypt to buy corn because of the famine. See Genesis 42:1-3.'),
('Genesis', 42, 'kids', 2, 'Did the brothers recognize Joseph when they saw him?', 'Yes, right away', 'No, they did not recognize him', 'Only Reuben recognized him', 'Only Benjamin knew', 'b', 'Joseph knew his brethren but they knew not him. See Genesis 42:8.'),
('Genesis', 42, 'kids', 3, 'Which brother did Jacob refuse to send to Egypt?', 'Reuben', 'Judah', 'Benjamin', 'Simeon', 'c', 'Jacob would not send Benjamin lest mischief befall him. See Genesis 42:4.'),
-- Ch42 Teens
('Genesis', 42, 'teens', 1, 'What did Joseph accuse his brothers of being?', 'Thieves', 'Criminals', 'Liars', 'Spies who came to see the nakedness of the land', 'd', 'Joseph said "Ye are spies; to see the nakedness of the land ye are come." See Genesis 42:9.'),
('Genesis', 42, 'teens', 2, 'Which brother was kept behind in Egypt as a hostage?', 'Reuben', 'Simeon', 'Levi', 'Judah', 'b', 'Joseph took Simeon and bound him before their eyes. See Genesis 42:24.'),
('Genesis', 42, 'teens', 3, 'What did the brothers find in their sacks on the way home?', 'Extra grain', 'Gifts from Pharaoh', 'A note from Joseph', 'Their money had been returned in the mouths of their sacks', 'd', 'Every man''s money was in the mouth of his sack. See Genesis 42:27-28.'),
('Genesis', 42, 'teens', 4, 'How did Jacob react when the brothers asked to take Benjamin?', 'He refused and said they had bereaved him of his children', 'He agreed easily', 'He was indifferent', 'He suggested sending a servant instead', 'a', 'Jacob said "Me have ye bereaved of my children." See Genesis 42:36.'),
('Genesis', 42, 'teens', 5, 'What did Joseph do privately when he heard his brothers speaking about their guilt?', 'He laughed', 'He called his guards', 'He turned himself about from them and wept', 'He prayed', 'c', 'Joseph turned from them and wept. See Genesis 42:24.'),
-- Ch42 Adults
('Genesis', 42, 'adults', 1, 'How many brothers came to Egypt the first time?', 'Eleven', 'Nine', 'Twelve', 'Ten', 'd', 'Ten of Joseph''s brethren went down to buy corn. See Genesis 42:3.'),
('Genesis', 42, 'adults', 2, 'What earlier event did the brothers recall that caused them guilt?', 'Selling their birthright', 'Lying to Isaac', 'They said they were guilty concerning their brother Joseph because they saw the anguish of his soul when he besought them and they would not hear', 'Stealing Laban''s goods', 'c', 'They recalled seeing Joseph''s anguish and ignoring his pleas. See Genesis 42:21.'),
('Genesis', 42, 'adults', 3, 'What did Reuben say to his brothers about their guilt?', 'Forget about it', 'Spake I not unto you saying do not sin against the child and ye would not hear; therefore his blood is required', 'It was all Judah''s fault', 'God has forgiven us', 'b', 'Reuben reminded them he had warned them not to sin against the child. See Genesis 42:22.'),
('Genesis', 42, 'adults', 4, 'Why did Joseph speak through an interpreter with his brothers?', 'To maintain his disguise since they knew not that Joseph understood them', 'He had forgotten Hebrew', 'Egyptian law required it', 'He wanted to confuse them', 'a', 'Joseph used an interpreter and they knew not he understood them. See Genesis 42:23.'),
('Genesis', 42, 'adults', 5, 'What condition did Joseph set for proving the brothers were not spies?', 'They must bring gold', 'They must serve in Egypt', 'They must bring their youngest brother to him', 'They must bring their father', 'c', 'Joseph demanded they bring their youngest brother. See Genesis 42:15-20.'),
('Genesis', 42, 'adults', 6, 'What desperate offer did Reuben make to Jacob to persuade him to release Benjamin?', 'Slay my two sons if I bring him not to thee', 'All his possessions', 'He would stay in Egypt instead', 'He would forfeit his birthright', 'a', 'Reuben said "Slay my two sons, if I bring him not to thee." See Genesis 42:37.'),
('Genesis', 42, 'adults', 7, 'How did Jacob describe his state when refusing to send Benjamin?', 'He was angry', 'He was hopeful', 'He was merely cautious', 'He said if mischief befall Benjamin ye shall bring down my gray hairs with sorrow to the grave', 'd', 'Jacob feared his gray hairs would go down to the grave in sorrow. See Genesis 42:38.'),
('Genesis', 42, 'adults', 8, 'What does Joseph''s testing of his brothers reveal about his character?', 'He wanted revenge', 'He was testing whether they had changed and would now protect the youngest brother Benjamin as they had failed to protect him', 'He was playing games', 'He was confused', 'b', 'Joseph tested whether his brothers would sacrifice Benjamin as they had sacrificed him. See Genesis 42:15-20.');

-- ═══ Genesis Chapters 43–47 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Ch43 Kids
('Genesis', 43, 'kids', 1, 'Why did the brothers have to go back to Egypt?', 'They ran out of food and needed more grain', 'They missed Simeon', 'Joseph invited them', 'Pharaoh ordered them to return', 'a', 'The famine was sore and they had eaten all the corn they brought. See Genesis 43:1-2.'),
('Genesis', 43, 'kids', 2, 'Who went with the brothers on the second trip that did not go the first time?', 'Jacob', 'Benjamin', 'A servant', 'Reuben''s sons', 'b', 'Jacob finally allowed Benjamin to go. See Genesis 43:13.'),
('Genesis', 43, 'kids', 3, 'When Joseph invited his brothers to eat at his house, how much more food did Benjamin get than the others?', 'Twice as much', 'Three times as much', 'Five times as much', 'The same as everyone', 'c', 'Benjamin''s mess was five times so much as any of theirs. See Genesis 43:34.'),
-- Ch43 Teens
('Genesis', 43, 'teens', 1, 'Which brother pledged to be personally responsible for Benjamin''s safety?', 'Reuben', 'Levi', 'Simeon', 'Judah', 'd', 'Judah said "I will be surety for him; of my hand shalt thou require him." See Genesis 43:9.'),
('Genesis', 43, 'teens', 2, 'What gifts did Jacob send with the brothers to the ruler of Egypt?', 'Gold and silver only', 'Balm, honey, spices, myrrh, nuts, and almonds plus double money', 'Livestock and grain', 'Fine clothing and jewels', 'b', 'Jacob sent a present of balm, honey, spices, myrrh, nuts, and almonds. See Genesis 43:11.'),
('Genesis', 43, 'teens', 3, 'What did the brothers fear when they were brought to Joseph''s house?', 'They would be killed', 'Joseph would torture them', 'They would never see Canaan again', 'They would be made bondmen because of the money found in their sacks', 'd', 'They feared being made slaves because of the money in their sacks. See Genesis 43:18.'),
('Genesis', 43, 'teens', 4, 'What did Joseph''s steward say about the money in the sacks?', 'Peace be to you; your God and the God of your father hath given you treasure; I had your money', 'He accused them of theft', 'He knew nothing about it', 'He demanded they return it', 'a', 'The steward said their God gave them treasure and that he had their money. See Genesis 43:23.'),
('Genesis', 43, 'teens', 5, 'What happened when Joseph saw Benjamin?', 'He was angry', 'He immediately revealed himself', 'His bowels did yearn upon his brother and he sought a place to weep', 'He ignored him', 'c', 'Joseph''s bowels yearned and he sought a place to weep. See Genesis 43:30.'),
-- Ch43 Adults
('Genesis', 43, 'adults', 1, 'What argument did Judah use to convince Jacob to send Benjamin?', 'He offered his wealth', 'He appealed to God', 'He threatened to go without permission', 'If they had not lingered they could have gone and returned twice by now; Judah personally guaranteed Benjamin''s safety', 'd', 'Judah guaranteed Benjamin and pointed out the delay. See Genesis 43:8-10.'),
('Genesis', 43, 'adults', 2, 'What resigned statement did Jacob make when finally agreeing to send Benjamin?', 'God will protect us', 'I trust you completely', 'If I be bereaved of my children, I am bereaved', 'Let us pray for safety', 'c', 'Jacob said "If I be bereaved of my children, I am bereaved." See Genesis 43:14.'),
('Genesis', 43, 'adults', 3, 'How did Joseph''s brothers present themselves when they arrived at his house?', 'They stood proudly', 'They bowed down to him to the earth with their present', 'They wept before him', 'They demanded to see Simeon', 'b', 'They bowed themselves to him to the earth. See Genesis 43:26.'),
('Genesis', 43, 'adults', 4, 'What question did Joseph ask about their father?', 'Is your father well? Is he yet alive?', 'Where does he live', 'Will he come to Egypt', 'How old is he', 'a', 'Joseph asked "Is your father well, the old man of whom ye spake? Is he yet alive?" See Genesis 43:27.'),
('Genesis', 43, 'adults', 5, 'What blessing did Joseph pronounce over Benjamin?', 'May you be wealthy', 'May you inherit the land', 'God be gracious unto thee, my son', 'Live long and prosper', 'c', 'Joseph said "God be gracious unto thee, my son." See Genesis 43:29.'),
('Genesis', 43, 'adults', 6, 'Why did the Egyptians eat separately from the Hebrews at the feast?', 'Because the Egyptians might not eat bread with the Hebrews, for that is an abomination unto them', 'Joseph ordered it', 'The room was too small', 'It was a custom of politeness', 'a', 'It was an abomination for Egyptians to eat with Hebrews. See Genesis 43:32.'),
('Genesis', 43, 'adults', 7, 'What astonished the brothers about the seating arrangement at the feast?', 'They sat next to Pharaoh', 'They sat on golden chairs', 'They were given Egyptian clothing', 'They were seated in order of age from firstborn to youngest and they marvelled', 'd', 'They were set in birth order and the men marvelled one at another. See Genesis 43:33.'),
('Genesis', 43, 'adults', 8, 'What is the significance of Benjamin receiving five times the portion of the others?', 'Joseph was wasteful', 'It tested whether the brothers would be jealous of favouritism toward Rachel''s son, as they had been jealous of Joseph', 'Egyptian custom required it', 'Benjamin was hungrier', 'b', 'The fivefold portion tested whether the brothers had overcome jealousy of Rachel''s sons. See Genesis 43:34.'),
-- Ch44 Kids
('Genesis', 44, 'kids', 1, 'What was secretly placed in Benjamin''s sack?', 'Joseph''s silver cup', 'Extra grain', 'A gold ring', 'A scroll', 'a', 'Joseph''s steward put the silver cup in Benjamin''s sack. See Genesis 44:2.'),
('Genesis', 44, 'kids', 2, 'Were the brothers telling the truth when they said they did not steal?', 'No, they were lying', 'Yes, they did not know the cup was placed there', 'Only some of them were honest', 'They had stolen it', 'b', 'The brothers were innocent; the cup was planted by Joseph''s steward. See Genesis 44:1-2.'),
('Genesis', 44, 'kids', 3, 'Which brother begged to stay as a slave instead of Benjamin?', 'Reuben', 'Simeon', 'Judah', 'Levi', 'c', 'Judah offered to be a servant instead of Benjamin. See Genesis 44:33.'),
-- Ch44 Teens
('Genesis', 44, 'teens', 1, 'What did the brothers do when the cup was found in Benjamin''s sack?', 'They blamed Benjamin', 'They fought the steward', 'They ran away', 'They rent their clothes and returned to the city', 'd', 'They rent their clothes, laded their asses, and returned to the city. See Genesis 44:13.'),
('Genesis', 44, 'teens', 2, 'What bold claim had the brothers made before the search?', 'They were innocent men', 'Let him with whom the cup is found die, and the rest would be bondmen', 'They would pay any fine', 'They would leave Egypt forever', 'b', 'They said the thief should die and the rest be servants. See Genesis 44:9.'),
('Genesis', 44, 'teens', 3, 'What did Judah say would happen to Jacob if Benjamin did not return?', 'Jacob would be angry', 'Jacob would send soldiers', 'Jacob would come to Egypt', 'Jacob would die, his gray hairs brought down with sorrow to the grave', 'd', 'Judah said their father would die of grief. See Genesis 44:29-31.'),
('Genesis', 44, 'teens', 4, 'What did Judah offer as an alternative to keeping Benjamin?', 'Let me abide instead of the lad as a bondman to my lord', 'Money and gold', 'All the brothers would stay', 'They would bring more gifts', 'a', 'Judah offered himself as slave in place of Benjamin. See Genesis 44:33.'),
('Genesis', 44, 'teens', 5, 'Why was Judah''s plea so important for what happened next?', 'It was entertaining', 'It was very short', 'It showed the brothers had changed and would now sacrifice themselves for Benjamin, which moved Joseph deeply', 'Joseph had expected money', 'c', 'Judah''s selfless plea proved the brothers had transformed. See Genesis 44:33-34.'),
-- Ch44 Adults
('Genesis', 44, 'adults', 1, 'What did Joseph instruct his steward to put in each brother''s sack besides grain?', 'Gifts', 'Egyptian trinkets', 'Letters', 'Each man''s money in the sack''s mouth, and the silver cup in Benjamin''s sack', 'd', 'The steward put every man''s money in his sack and the cup in Benjamin''s. See Genesis 44:1-2.'),
('Genesis', 44, 'adults', 2, 'What did Joseph say about the stolen cup?', 'It was merely a cup', 'It was worthless', 'Is not this it in which my lord drinketh and whereby indeed he divineth', 'It belonged to Pharaoh', 'c', 'The steward said it was used for drinking and divining. See Genesis 44:5.'),
('Genesis', 44, 'adults', 3, 'What did Joseph say when the brothers were brought back?', 'You are all guilty', 'What deed is this that ye have done? Wot ye not that such a man as I can certainly divine?', 'Return to Canaan', 'I forgive you', 'b', 'Joseph asked what they had done, claiming he could divine. See Genesis 44:15.'),
('Genesis', 44, 'adults', 4, 'What did Judah acknowledge about their situation?', 'God hath found out the iniquity of thy servants, acknowledging a deeper guilt beyond the cup', 'They were completely innocent', 'They deserved death', 'It was a misunderstanding', 'a', 'Judah said "God hath found out the iniquity of thy servants." See Genesis 44:16.'),
('Genesis', 44, 'adults', 5, 'How did Judah describe Jacob''s relationship to Benjamin?', 'Jacob loved all sons equally', 'Jacob did not care for Benjamin', 'His father loveth him and the lad''s brother is dead and he alone is left of his mother', 'Benjamin was independent', 'c', 'Judah explained Jacob''s special love for the surviving son of Rachel. See Genesis 44:20.'),
('Genesis', 44, 'adults', 6, 'What phrase did Judah use to describe the bond between Jacob and Benjamin?', 'His life is bound up in the lad''s life', 'Mere affection', 'They are close', 'He depends on him', 'a', 'Judah said "his life is bound up in the lad''s life." See Genesis 44:30.'),
('Genesis', 44, 'adults', 7, 'How does Judah''s offer to substitute himself for Benjamin prefigure a biblical theme?', 'It foreshadows nothing', 'It shows legal customs', 'It illustrates family duty only', 'It prefigures substitutionary atonement, where one takes the place of another, pointing toward Christ', 'd', 'Judah''s willingness to take Benjamin''s punishment prefigures substitutionary sacrifice. See Genesis 44:33.'),
('Genesis', 44, 'adults', 8, 'How had Judah changed from the man who suggested selling Joseph in chapter 37?', 'He had not changed at all', 'He went from callously selling one of Rachel''s sons to offering his own freedom to save the other, showing profound moral transformation', 'He was merely desperate', 'He acted out of self-interest', 'b', 'Judah''s transformation from selling Joseph to sacrificing for Benjamin is a key character arc. See Genesis 37:26-27 and 44:33.'),
-- Ch45 Kids
('Genesis', 45, 'kids', 1, 'What did Joseph finally tell his brothers?', 'I am Joseph! Is my father still alive?', 'He told them to leave Egypt', 'He told them to bring gold', 'He said he was Pharaoh', 'a', 'Joseph said "I am Joseph; doth my father yet live?" See Genesis 45:3.'),
('Genesis', 45, 'kids', 2, 'Was Joseph angry at his brothers for selling him?', 'Yes, he punished them', 'No, he said God sent him before them to preserve life', 'He wanted revenge', 'He ignored what they did', 'b', 'Joseph said "God did send me before you to preserve life." See Genesis 45:5.'),
('Genesis', 45, 'kids', 3, 'What did Joseph ask his brothers to do?', 'Stay in Egypt alone', 'Go home and never return', 'Go get their father Jacob and bring him to Egypt', 'Pay him money', 'c', 'Joseph said "Haste ye, and go up to my father, and bring him down." See Genesis 45:9, 13.'),
-- Ch45 Teens
('Genesis', 45, 'teens', 1, 'How did the brothers react when Joseph revealed himself?', 'They were happy immediately', 'They ran away', 'They accused him of lying', 'They could not answer him because they were troubled at his presence', 'd', 'His brethren could not answer him, for they were troubled at his presence. See Genesis 45:3.'),
('Genesis', 45, 'teens', 2, 'How did Joseph explain why he was in Egypt?', 'He blamed his brothers', 'God sent him before them to preserve a posterity and to save their lives by a great deliverance', 'He said it was bad luck', 'He said Pharaoh brought him', 'b', 'Joseph said God sent him to preserve a posterity and deliver them. See Genesis 45:7.'),
('Genesis', 45, 'teens', 3, 'Where did Joseph say his family should live in Egypt?', 'In the city of Memphis', 'Anywhere they chose', 'Near Pharaoh''s palace', 'In the land of Goshen', 'd', 'Joseph told them to dwell in the land of Goshen. See Genesis 45:10.'),
('Genesis', 45, 'teens', 4, 'How many more years of famine remained according to Joseph?', 'Five years', 'Two years', 'Three years', 'Seven years', 'a', 'Joseph said there were yet five years of famine remaining. See Genesis 45:6, 11.'),
('Genesis', 45, 'teens', 5, 'How did Pharaoh react to the news that Joseph''s brothers had come?', 'He was angry', 'He was indifferent', 'It pleased Pharaoh and his servants well, and he offered wagons and provisions', 'He told them to leave', 'c', 'It pleased Pharaoh well and he commanded Joseph to give them wagons. See Genesis 45:16-19.'),
-- Ch45 Adults
('Genesis', 45, 'adults', 1, 'What did Joseph do before revealing himself to ensure privacy?', 'He locked the doors', 'He sent a written note', 'He whispered', 'He caused every Egyptian to go out from him so no man stood with him', 'd', 'Joseph cried "Cause every man to go out from me." See Genesis 45:1.'),
('Genesis', 45, 'adults', 2, 'What theological statement did Joseph make about God''s sovereignty over his suffering?', 'God abandoned him', 'God was punishing the brothers', 'It was not you that sent me hither but God who made him a father to Pharaoh and lord of all Egypt', 'It was merely fate', 'c', 'Joseph said "it was not you that sent me hither, but God." See Genesis 45:8.'),
('Genesis', 45, 'adults', 3, 'Joseph wept so loudly upon revealing himself that who heard it?', 'Only his brothers', 'The Egyptians and the house of Pharaoh heard', 'No one heard', 'Only Benjamin heard', 'b', 'Joseph wept aloud and the Egyptians and Pharaoh''s house heard. See Genesis 45:2.'),
('Genesis', 45, 'adults', 4, 'What specific provision did Pharaoh offer Joseph''s family?', 'The good of all the land of Egypt and they would eat the fat of the land', 'Gold and silver', 'A palace', 'Military protection', 'a', 'Pharaoh said "the good of all the land of Egypt is yours." See Genesis 45:18-20.'),
('Genesis', 45, 'adults', 5, 'What extra gifts did Joseph give Benjamin compared to the other brothers?', 'The same as everyone', 'Ten changes of raiment', 'Three hundred pieces of silver and five changes of raiment versus one change each for the others', 'A house in Egypt', 'c', 'Benjamin got 300 pieces of silver and 5 changes of raiment; others got 1 change each. See Genesis 45:22.'),
('Genesis', 45, 'adults', 6, 'What parting instruction did Joseph give his brothers?', 'See that ye fall not out by the way, meaning do not quarrel on the journey', 'Travel quickly', 'Keep silent about him', 'Take different routes', 'a', 'Joseph said "See that ye fall not out by the way." See Genesis 45:24.'),
('Genesis', 45, 'adults', 7, 'How did Jacob respond when first told Joseph was alive?', 'He believed immediately', 'He praised God', 'He wept with joy', 'Jacob''s heart fainted for he believed them not', 'd', 'Jacob''s heart fainted, for he believed them not. See Genesis 45:26.'),
('Genesis', 45, 'adults', 8, 'What finally convinced Jacob that Joseph was alive?', 'A letter from Joseph', 'When he saw the wagons Joseph had sent, the spirit of Jacob revived', 'The brothers swore an oath', 'A dream from God', 'b', 'When Jacob saw the wagons, his spirit revived. See Genesis 45:27.'),
-- Ch46 Kids
('Genesis', 46, 'kids', 1, 'Where did God speak to Jacob on his way to Egypt?', 'At Beersheba', 'At Bethel', 'At Hebron', 'At Shechem', 'a', 'God spake unto Israel in the visions of the night at Beer-sheba. See Genesis 46:1-2.'),
('Genesis', 46, 'kids', 2, 'How many of Jacob''s family went to Egypt?', 'Fifty', 'Seventy', 'One hundred', 'Forty', 'b', 'All the souls of the house of Jacob which came into Egypt were threescore and ten (70). See Genesis 46:27.'),
('Genesis', 46, 'kids', 3, 'How did Joseph greet his father Jacob?', 'He waved from far away', 'He sent a servant to meet him', 'He fell on his neck and wept a good while', 'He bowed before him', 'c', 'Joseph fell on Jacob''s neck and wept on his neck a good while. See Genesis 46:29.'),
-- Ch46 Teens
('Genesis', 46, 'teens', 1, 'What did God promise Jacob at Beersheba?', 'He would return to Canaan immediately', 'He would give him a long life', 'He would defeat the Egyptians', 'He would make Jacob a great nation in Egypt and would surely bring him up again', 'd', 'God promised to make Jacob a great nation there and to bring him up again. See Genesis 46:3-4.'),
('Genesis', 46, 'teens', 2, 'What comforting promise did God add about Joseph?', 'Joseph would visit Canaan', 'Joseph shall put his hand upon thine eyes, meaning Joseph would be with Jacob when he died', 'Joseph would become king', 'Joseph would return with him', 'b', 'God said Joseph would put his hand upon Jacob''s eyes. See Genesis 46:4.'),
('Genesis', 46, 'teens', 3, 'Which son did Jacob send ahead to prepare for the family''s arrival?', 'Reuben', 'Benjamin', 'Simeon', 'Judah, to direct the way to Goshen', 'd', 'Jacob sent Judah before him unto Joseph to direct his face unto Goshen. See Genesis 46:28.'),
('Genesis', 46, 'teens', 4, 'What did Jacob say to Joseph when they were reunited?', 'Now let me die, since I have seen thy face, because thou art yet alive', 'I am proud of you', 'Let us return to Canaan together', 'I never thought this would happen', 'a', 'Israel said "Now let me die, since I have seen thy face." See Genesis 46:30.'),
('Genesis', 46, 'teens', 5, 'What did Joseph tell his family to say to Pharaoh about their occupation?', 'They were farmers', 'They were merchants', 'They were shepherds, because every shepherd is an abomination unto the Egyptians, which would help them settle separately in Goshen', 'They were builders', 'c', 'Joseph coached them to say they were shepherds so they could dwell in Goshen. See Genesis 46:33-34.'),
-- Ch46 Adults
('Genesis', 46, 'adults', 1, 'What sacrifices did Jacob offer at Beersheba before continuing to Egypt?', 'Burnt offerings', 'Peace offerings', 'Grain offerings', 'Sacrifices unto the God of his father Isaac', 'd', 'Israel offered sacrifices unto the God of his father Isaac. See Genesis 46:1.'),
('Genesis', 46, 'adults', 2, 'How did God address Jacob in the vision?', 'Israel', 'Son of Isaac', 'Jacob, Jacob', 'My servant', 'c', 'God said "Jacob, Jacob" and he said "Here am I." See Genesis 46:2.'),
('Genesis', 46, 'adults', 3, 'What reassurance did God give about going to Egypt?', 'It would be brief', 'Fear not to go down into Egypt for I will there make of thee a great nation', 'Egypt would welcome them', 'The famine would end soon', 'b', 'God told Jacob not to fear because He would make a great nation there. See Genesis 46:3.'),
('Genesis', 46, 'adults', 4, 'The number seventy souls includes which notable grandchildren?', 'Er and Onan (who died in Canaan), plus Joseph and his two sons already in Egypt', 'Only sons', 'Only those born in Egypt', 'No grandchildren', 'a', 'The seventy includes Er and Onan who died, and Joseph, Manasseh, and Ephraim in Egypt. See Genesis 46:12, 20, 27.'),
('Genesis', 46, 'adults', 5, 'How many of the seventy souls came through Leah''s line?', 'Twelve', 'Twenty', 'Thirty and three', 'Forty', 'c', 'The souls through Leah were thirty and three. See Genesis 46:15.'),
('Genesis', 46, 'adults', 6, 'Why was it strategically important for Jacob''s family to settle in Goshen?', 'Goshen was separate from mainstream Egyptian society, allowing them to maintain their identity as shepherds while being near Joseph', 'It was the most fertile land', 'It was closest to Canaan', 'Pharaoh ordered it', 'a', 'Goshen provided separation to preserve their distinct identity. See Genesis 46:34.'),
('Genesis', 46, 'adults', 7, 'What is the significance of God saying "I will go down with thee into Egypt"?', 'God would send an angel', 'God would protect the journey', 'It was a metaphor only', 'God personally accompanying Jacob assured him that leaving the Promised Land was within God''s plan, not abandoning the covenant', 'd', 'God''s presence affirmed that Egypt was part of His covenant plan. See Genesis 46:4.'),
('Genesis', 46, 'adults', 8, 'How does Jacob''s descent into Egypt with seventy souls connect to Deuteronomy 10:22?', 'It does not connect', 'Moses later referenced that their fathers went down to Egypt with seventy persons and God made them as the stars of heaven for multitude', 'It contradicts Deuteronomy', 'Only the number is the same', 'b', 'Moses recalled the seventy who became a great multitude. See Genesis 46:27 and Deuteronomy 10:22.'),
-- Ch47 Kids
('Genesis', 47, 'kids', 1, 'Where did Jacob''s family settle in Egypt?', 'In the land of Goshen', 'By the Nile River', 'In Pharaoh''s palace', 'In a desert', 'a', 'Joseph placed his family in the land of Goshen (Rameses). See Genesis 47:11.'),
('Genesis', 47, 'kids', 2, 'Did Jacob meet Pharaoh?', 'No, he was too afraid', 'Yes, and Jacob blessed Pharaoh', 'Only Joseph met Pharaoh', 'They met by accident', 'b', 'Joseph brought Jacob before Pharaoh and Jacob blessed Pharaoh. See Genesis 47:7.'),
('Genesis', 47, 'kids', 3, 'How old did Jacob say he was when Pharaoh asked?', 'One hundred years', 'Ninety years', 'A hundred and thirty years', 'Two hundred years', 'c', 'Jacob said "The days of the years of my pilgrimage are an hundred and thirty years." See Genesis 47:9.'),
-- Ch47 Teens
('Genesis', 47, 'teens', 1, 'How did Jacob describe his life to Pharaoh?', 'Long and blessed', 'Ordinary and peaceful', 'Wonderful and prosperous', 'Few and evil have the days of the years of my life been', 'd', 'Jacob said his days were few and evil. See Genesis 47:9.'),
('Genesis', 47, 'teens', 2, 'What did the Egyptians eventually give to Joseph in exchange for food during the famine?', 'Only money', 'First their money, then livestock, then their land, and finally themselves as servants', 'Their clothing', 'Their houses only', 'b', 'They gave money, then cattle, then land, then themselves. See Genesis 47:14-21.'),
('Genesis', 47, 'teens', 3, 'What percentage of crops did Joseph require Egyptians to give Pharaoh?', 'One tenth', 'One third', 'One half', 'One fifth (twenty percent)', 'd', 'Joseph made it a law to give the fifth part unto Pharaoh. See Genesis 47:26.'),
('Genesis', 47, 'teens', 4, 'Whose land was the only land not bought by Pharaoh?', 'The priests'' land, because they had a portion from Pharaoh', 'The merchants'' land', 'The soldiers'' land', 'The nobles'' land', 'a', 'Only the land of the priests bought he not, for they had a portion from Pharaoh. See Genesis 47:22.'),
('Genesis', 47, 'teens', 5, 'What request did Jacob make to Joseph near the end of his life?', 'Build me a tomb in Egypt', 'Give all my possessions to Benjamin', 'Bury me not in Egypt but carry me out to be buried with my fathers', 'Let me see Pharaoh one more time', 'c', 'Jacob asked Joseph to bury him with his fathers, not in Egypt. See Genesis 47:29-30.'),
-- Ch47 Adults
('Genesis', 47, 'adults', 1, 'How many of Joseph''s brothers did he present to Pharaoh?', 'All twelve', 'Two brothers', 'Only Judah and Benjamin', 'Five of his brethren', 'd', 'Joseph took five of his brethren and presented them to Pharaoh. See Genesis 47:2.'),
('Genesis', 47, 'adults', 2, 'How many times did Jacob bless Pharaoh?', 'Once', 'Three times', 'Twice, upon arrival and departure', 'He did not bless Pharaoh', 'c', 'Jacob blessed Pharaoh both when he came in and when he left. See Genesis 47:7, 10.'),
('Genesis', 47, 'adults', 3, 'Jacob said his years had not attained to the years of his fathers. How old were Abraham and Isaac when they died?', 'Abraham 150, Isaac 160', 'Abraham 175, Isaac 180', 'Abraham 200, Isaac 190', 'Abraham 180, Isaac 175', 'b', 'Abraham died at 175 (Genesis 25:7) and Isaac at 180 (Genesis 35:28). Jacob was 130 at this point.'),
('Genesis', 47, 'adults', 4, 'Joseph gathered all the money in Egypt and Canaan. Where did he bring it?', 'He brought it into Pharaoh''s house', 'He kept it', 'He distributed it to the poor', 'He buried it', 'a', 'Joseph brought the money into Pharaoh''s house. See Genesis 47:14.'),
('Genesis', 47, 'adults', 5, 'What did Joseph do with the Egyptian people after buying their land?', 'He enslaved them permanently', 'He sent them away', 'He removed them to cities from one end of the borders of Egypt to the other', 'He freed them', 'c', 'Joseph removed the people to cities from one end of Egypt to the other. See Genesis 47:21.'),
('Genesis', 47, 'adults', 6, 'What oath did Joseph swear to Jacob regarding his burial?', 'Jacob asked Joseph to put his hand under his thigh and swear not to bury him in Egypt', 'A simple promise', 'A written contract', 'A verbal agreement', 'a', 'Jacob said "Put thy hand under my thigh" and swear. See Genesis 47:29-30.'),
('Genesis', 47, 'adults', 7, 'How did Israel respond after Joseph swore the oath about burial?', 'He fell asleep', 'He blessed Joseph', 'He wept', 'Israel bowed himself upon the bed''s head', 'd', 'Israel bowed himself upon the bed''s head. See Genesis 47:31.'),
('Genesis', 47, 'adults', 8, 'What does Joseph''s economic policy during the famine reveal about his administrative approach?', 'He was greedy', 'He centralised all resources under Pharaoh but provided seed for planting and kept the people alive, balancing survival with governance', 'He gave everything away freely', 'He only helped Israelites', 'b', 'Joseph preserved life while consolidating resources under Pharaoh. See Genesis 47:23-26.');

-- ═══ Genesis Chapters 48–50 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Ch48 Kids
('Genesis', 48, 'kids', 1, 'Whose two sons did Jacob bless in this chapter?', 'Joseph''s sons Ephraim and Manasseh', 'Judah''s sons', 'Reuben''s sons', 'Benjamin''s sons', 'a', 'Jacob blessed Joseph''s two sons Ephraim and Manasseh. See Genesis 48:1, 5.'),
('Genesis', 48, 'kids', 2, 'What unusual thing did Jacob do with his hands when blessing the boys?', 'He raised them high', 'He crossed his hands and put his right hand on the younger son''s head', 'He clapped them together', 'He folded them in prayer', 'b', 'Israel stretched out his right hand and laid it upon Ephraim''s head, who was the younger, crossing his hands. See Genesis 48:14.'),
('Genesis', 48, 'kids', 3, 'Which son received the greater blessing?', 'Manasseh the older', 'They received the same', 'Ephraim the younger', 'Neither was blessed', 'c', 'Jacob set Ephraim before Manasseh, giving the younger the greater blessing. See Genesis 48:19-20.'),
-- Ch48 Teens
('Genesis', 48, 'teens', 1, 'What did Jacob declare about Ephraim and Manasseh?', 'They would serve Joseph', 'They were not his grandchildren', 'They should return to Canaan', 'They would be counted as his own sons, like Reuben and Simeon, receiving tribal inheritance', 'd', 'Jacob adopted them saying "they are mine; as Reuben and Simeon, they shall be mine." See Genesis 48:5.'),
('Genesis', 48, 'teens', 2, 'Why did Joseph try to move Jacob''s right hand to Manasseh''s head?', 'He thought Jacob made a mistake', 'Joseph was displeased because Manasseh was the firstborn and should have the right hand', 'Manasseh asked for it', 'It was Egyptian custom', 'b', 'Joseph tried to move Jacob''s hand because Manasseh was the firstborn. See Genesis 48:17-18.'),
('Genesis', 48, 'teens', 3, 'What did Jacob say about why he put Ephraim first?', 'He liked Ephraim better', 'He was confused', 'God told him in a dream', 'He knew what he was doing; Manasseh would be great but Ephraim would be greater and his seed would become a multitude of nations', 'd', 'Jacob said Ephraim''s seed shall become a multitude of nations. See Genesis 48:19.'),
('Genesis', 48, 'teens', 4, 'What did Jacob tell Joseph about Rachel?', 'Rachel died by him in Canaan on the way to Ephrath, which is Bethlehem', 'She was still alive', 'She was buried in Egypt', 'He did not mention her', 'a', 'Jacob mentioned Rachel''s death and burial near Bethlehem. See Genesis 48:7.'),
('Genesis', 48, 'teens', 5, 'What blessing formula did Jacob establish for Israel using these boys?', 'May God bless you', 'May you be strong as lions', 'In thee shall Israel bless, saying God make thee as Ephraim and as Manasseh', 'May your fields be fruitful', 'c', 'Jacob said "In thee shall Israel bless, saying, God make thee as Ephraim and as Manasseh." See Genesis 48:20.'),
-- Ch48 Adults
('Genesis', 48, 'adults', 1, 'What appearance of God did Jacob recall when blessing Ephraim and Manasseh?', 'The burning bush', 'The angel at Peniel', 'The voice at Moriah', 'God Almighty appeared to him at Luz (Bethel) in Canaan and blessed him', 'd', 'Jacob recalled God Almighty appearing to him at Luz. See Genesis 48:3.'),
('Genesis', 48, 'adults', 2, 'How did Jacob describe the angel who redeemed him?', 'An angel of wrath', 'A ministering spirit', 'The Angel which redeemed me from all evil, bless the lads', 'The angel of death', 'c', 'Jacob invoked "The Angel which redeemed me from all evil." See Genesis 48:16.'),
('Genesis', 48, 'adults', 3, 'What did Jacob say his name and the names of Abraham and Isaac should be upon?', 'A monument', 'Upon the lads Ephraim and Manasseh, and let them grow into a multitude', 'A scroll', 'An altar', 'b', 'Jacob said "let my name be named on them, and the name of my fathers." See Genesis 48:16.'),
('Genesis', 48, 'adults', 4, 'What extra portion did Jacob give Joseph beyond his brothers?', 'One portion above thy brethren which I took from the Amorite with my sword and bow', 'Double the money', 'The birthright blessing', 'All of Goshen', 'a', 'Jacob gave Joseph one portion (Shechem) above his brethren. See Genesis 48:22.'),
('Genesis', 48, 'adults', 5, 'What is the Hebrew word for the portion Jacob gave Joseph, and what city does it refer to?', 'Bethel', 'Hebron', 'Shechem, meaning both "shoulder/portion" and the city of Shechem', 'Bethlehem', 'c', 'The Hebrew word shechem means shoulder or portion, and refers to the city. See Genesis 48:22.'),
('Genesis', 48, 'adults', 6, 'How does Jacob''s crossing of hands continue a pattern seen throughout Genesis?', 'It continues the pattern of the younger being chosen over the elder: Isaac over Ishmael, Jacob over Esau, now Ephraim over Manasseh', 'It was accidental', 'It was Egyptian custom', 'It had no deeper meaning', 'a', 'God consistently chose the younger over the elder throughout Genesis. See Genesis 48:14, 19.'),
('Genesis', 48, 'adults', 7, 'What did Jacob acknowledge about his own failing eyesight?', 'He could see perfectly', 'He had been healed', 'He was completely blind', 'His eyes were dim for age so that he could not see clearly, paralleling his father Isaac', 'd', 'Israel''s eyes were dim for age. See Genesis 48:10.'),
('Genesis', 48, 'adults', 8, 'What prophetic statement did Jacob make about Israel''s future relationship with Canaan?', 'They would stay in Egypt forever', 'God shall be with you and bring you again unto the land of your fathers', 'They would conquer Egypt', 'They would become Egyptians', 'b', 'Jacob prophesied God would bring them back to Canaan. See Genesis 48:21.'),
-- Ch49 Kids
('Genesis', 49, 'kids', 1, 'What did Jacob do before he died?', 'He gave a special blessing or prophecy to each of his twelve sons', 'He wrote a letter', 'He built an altar', 'He sang a song', 'a', 'Jacob called his sons and blessed them, every one with his own blessing. See Genesis 49:1, 28.'),
('Genesis', 49, 'kids', 2, 'What animal did Jacob compare Judah to?', 'A lamb', 'A lion', 'An eagle', 'A bear', 'b', 'Jacob said "Judah is a lion''s whelp." See Genesis 49:9.'),
('Genesis', 49, 'kids', 3, 'Where did Jacob ask to be buried?', 'In Egypt', 'At Bethel', 'In the cave of Machpelah where Abraham, Sarah, Isaac, and Rebekah were buried', 'By the river Jordan', 'c', 'Jacob asked to be buried in the cave of Machpelah. See Genesis 49:29-30.'),
-- Ch49 Teens
('Genesis', 49, 'teens', 1, 'Why did Reuben lose his place of honour as firstborn?', 'He was lazy', 'He married a Canaanite', 'He sold Joseph', 'He was unstable as water and had defiled his father''s bed by lying with Bilhah', 'd', 'Reuben defiled his father''s couch and was called unstable as water. See Genesis 49:3-4.'),
('Genesis', 49, 'teens', 2, 'What did Jacob prophesy about Judah and the sceptre?', 'Judah would lose power', 'The sceptre shall not depart from Judah nor a lawgiver from between his feet until Shiloh come', 'Judah would become a priest', 'Judah would be scattered', 'b', 'Jacob prophesied the sceptre would remain with Judah until Shiloh come. See Genesis 49:10.'),
('Genesis', 49, 'teens', 3, 'What animal did Jacob compare Dan to?', 'A lion', 'A wolf', 'An eagle', 'A serpent by the way, an adder in the path', 'd', 'Jacob said "Dan shall be a serpent by the way, an adder in the path." See Genesis 49:17.'),
('Genesis', 49, 'teens', 4, 'What did Jacob say about Joseph?', 'Joseph is a fruitful bough by a well whose branches run over the wall', 'He would be weak', 'Joseph would rule Egypt forever', 'Joseph would return to Canaan alone', 'a', 'Jacob described Joseph as a fruitful bough by a well. See Genesis 49:22.'),
('Genesis', 49, 'teens', 5, 'What animal did Jacob compare Benjamin to?', 'A lamb', 'A horse', 'A wolf that raveneth, dividing the spoil', 'An ox', 'c', 'Jacob said "Benjamin shall ravin as a wolf." See Genesis 49:27.'),
-- Ch49 Adults
('Genesis', 49, 'adults', 1, 'What does the Shiloh prophecy in Genesis 49:10 traditionally signify?', 'A city name only', 'A peace treaty', 'A tribal boundary marker', 'A Messianic prophecy that the ruler would come from Judah''s line, understood as a reference to Christ', 'd', 'Shiloh is widely interpreted as a Messianic title meaning "he to whom it belongs." See Genesis 49:10.'),
('Genesis', 49, 'adults', 2, 'What prophecy did Jacob give about Simeon and Levi together?', 'They would be blessed with land', 'They would be priests together', 'He cursed their anger and said he would divide them in Jacob and scatter them in Israel', 'They would be mighty warriors', 'c', 'Jacob cursed their fierce anger and said they would be scattered. See Genesis 49:5-7.'),
('Genesis', 49, 'adults', 3, 'What did Jacob say about Zebulun''s future location?', 'In the mountains', 'He shall dwell at the haven of the sea and be for an haven of ships, and his border unto Zidon', 'In the desert', 'Near Jerusalem', 'b', 'Zebulun would dwell by the sea as a haven of ships. See Genesis 49:13.'),
('Genesis', 49, 'adults', 4, 'How did Jacob describe Issachar?', 'A strong ass couching down between two burdens', 'A mighty warrior', 'A swift runner', 'A great leader', 'a', 'Issachar is a strong ass couching down between two burdens. See Genesis 49:14.'),
('Genesis', 49, 'adults', 5, 'What did Jacob say about Naphtali?', 'He would be a judge', 'He would conquer many nations', 'He is a hind (doe) let loose who giveth goodly words', 'He would be a farmer', 'c', 'Naphtali is a hind let loose, he giveth goodly words. See Genesis 49:21.'),
('Genesis', 49, 'adults', 6, 'What specific blessings did Jacob pronounce upon Joseph?', 'Blessings of heaven above, blessings of the deep, blessings of the breasts and of the womb, prevailing unto the utmost bound of the everlasting hills', 'Wealth only', 'Military victories', 'A large family only', 'a', 'Jacob gave Joseph blessings of heaven, deep, breasts, and womb. See Genesis 49:25-26.'),
('Genesis', 49, 'adults', 7, 'Who are specifically named as buried in the cave of Machpelah?', 'Abraham and Sarah only', 'Abraham, Isaac, and Jacob only', 'All twelve sons', 'Abraham, Sarah, Isaac, Rebekah, and Leah', 'd', 'Abraham, Sarah, Isaac, Rebekah, and Leah are named as buried there. See Genesis 49:31.'),
('Genesis', 49, 'adults', 8, 'What did Jacob do immediately after finishing his blessings and burial instructions?', 'He fell asleep', 'He gathered up his feet into the bed, yielded up the ghost, and was gathered unto his people', 'He prayed', 'He called for Joseph', 'b', 'Jacob gathered his feet into the bed, yielded up the ghost, and was gathered unto his people. See Genesis 49:33.'),
-- Ch50 Kids
('Genesis', 50, 'kids', 1, 'Where was Jacob buried?', 'In the cave of Machpelah in Canaan', 'In Egypt', 'At Bethel', 'In the Jordan valley', 'a', 'They buried Jacob in the cave of Machpelah. See Genesis 50:13.'),
('Genesis', 50, 'kids', 2, 'What kind words did Joseph say to his brothers after their father died?', 'He was angry at them', 'You meant it for evil but God meant it for good to save many people', 'He told them to leave', 'He said nothing', 'b', 'Joseph said "ye thought evil against me; but God meant it unto good." See Genesis 50:20.'),
('Genesis', 50, 'kids', 3, 'How old was Joseph when he died?', 'Ninety years old', 'One hundred and twenty years old', 'A hundred and ten years old', 'Eighty years old', 'c', 'Joseph died being an hundred and ten years old. See Genesis 50:26.'),
-- Ch50 Teens
('Genesis', 50, 'teens', 1, 'What did the Egyptians do when Jacob died?', 'Nothing', 'They ignored his death', 'They celebrated', 'They mourned for him seventy days and embalmed him', 'd', 'The Egyptians mourned Jacob seventy days, and the physicians embalmed him. See Genesis 50:2-3.'),
('Genesis', 50, 'teens', 2, 'What were the brothers afraid of after Jacob''s death?', 'Losing their land', 'That Joseph would now take revenge on them for selling him', 'That Pharaoh would expel them', 'That famine would return', 'b', 'The brothers feared Joseph would hate them and requite their evil. See Genesis 50:15.'),
('Genesis', 50, 'teens', 3, 'What message did the brothers claim Jacob had left for Joseph?', 'Give them more land', 'Send them back to Canaan', 'Make them rulers in Egypt', 'Forgive the trespass of thy brethren and their sin, for they did unto thee evil', 'd', 'They said Jacob commanded Joseph to forgive them. See Genesis 50:16-17.'),
('Genesis', 50, 'teens', 4, 'What did Joseph do when his brothers fell down before him?', 'He wept and said fear not, for am I in the place of God', 'He turned away', 'He punished them', 'He ignored them', 'a', 'Joseph wept and told them not to fear. See Genesis 50:17-19.'),
('Genesis', 50, 'teens', 5, 'What promise did Joseph make his brothers swear about his bones?', 'To build him a great tomb', 'To bury him by the Nile', 'To carry his bones out of Egypt when God visited them and brought them to the promised land', 'To place him in Pharaoh''s tomb', 'c', 'Joseph made them swear to carry his bones out of Egypt. See Genesis 50:25.'),
-- Ch50 Adults
('Genesis', 50, 'adults', 1, 'How long did the mourning for Jacob last in total, including the Egyptian and Canaanite periods?', 'Forty days', 'Thirty days', 'One hundred days', 'Seventy days of Egyptian mourning plus seven days at the threshing floor of Atad', 'd', 'Seventy days in Egypt and seven more at the threshing floor of Atad. See Genesis 50:3-4, 10.'),
('Genesis', 50, 'adults', 2, 'What did the Canaanites call the place of mourning when they saw the grieving?', 'Valley of tears', 'Machpelah', 'Abel-mizraim, meaning the mourning of the Egyptians', 'Beth-aven', 'c', 'They called it Abel-mizraim (mourning of Egypt). See Genesis 50:11.'),
('Genesis', 50, 'adults', 3, 'What is the full statement of Joseph about God''s sovereignty in Genesis 50:20?', 'God is good', 'Ye thought evil against me but God meant it unto good, to bring to pass as it is this day, to save much people alive', 'God forgives all', 'Everything happens for a reason', 'b', 'Joseph declared God turned their evil intent into good to save many lives. See Genesis 50:20.'),
('Genesis', 50, 'adults', 4, 'What did Joseph say about his role in relation to God when his brothers were afraid?', 'Am I in the place of God? Fear not, I will nourish you and your little ones', 'I am your ruler', 'I will decide your fate', 'God has abandoned you', 'a', 'Joseph humbly said "Am I in the place of God?" See Genesis 50:19-21.'),
('Genesis', 50, 'adults', 5, 'What did Joseph prophesy to his brothers before he died?', 'Egypt would fall', 'They would become Egyptians', 'God will surely visit you and bring you out of this land unto the land which he sware to Abraham, Isaac, and Jacob', 'The famine would return', 'c', 'Joseph said "God will surely visit you, and bring you out of this land." See Genesis 50:24.'),
('Genesis', 50, 'adults', 6, 'What was done with Joseph''s body after death?', 'He was embalmed and put in a coffin in Egypt', 'He was buried immediately', 'He was cremated', 'He was buried at Machpelah', 'a', 'They embalmed Joseph and he was put in a coffin in Egypt. See Genesis 50:26.'),
('Genesis', 50, 'adults', 7, 'How does Genesis 50:20 serve as a theological summary of the entire Joseph narrative?', 'It summarises Joseph''s career', 'It only applies to Joseph', 'It is a minor detail', 'It demonstrates that God sovereignly works through human evil to accomplish His redemptive purposes, a theme running from the brothers'' betrayal through famine relief', 'd', 'Genesis 50:20 encapsulates divine sovereignty over human sin for redemptive ends.'),
('Genesis', 50, 'adults', 8, 'Joseph''s instruction about his bones was fulfilled centuries later. When and by whom?', 'By David when he became king', 'By Moses during the Exodus, as recorded in Exodus 13:19, and Joseph was finally buried at Shechem per Joshua 24:32', 'By Solomon at the temple', 'It was never fulfilled', 'b', 'Moses took Joseph''s bones at the Exodus and they were buried at Shechem. See Exodus 13:19 and Joshua 24:32.');
